/**
 * Global current-page override registry.
 *
 * Allows mock stores / dev environments to override `window.location.href`
 * in all API and WebSocket payloads. When set, all SDK code that sends
 * `current_page` will use this value instead of `window.location.href`.
 */

let override: string | null = null;

/**
 * Set the current-page override. Pass `null` to clear.
 */
export function setCurrentPageOverride(url: string | null): void {
  override = url;
}

/**
 * Get the current page URL. Returns the override if set,
 * otherwise falls back to `window.location.href`.
 */
export function getCurrentPage(): string {
  if (override) return override;
  return typeof window !== 'undefined' ? window.location.href : '';
}
