import React, { useState, useEffect, useRef } from 'react';

const statusConfig: Record<string, { texts: string[] }> = {
    thinking: {
        texts: [
            'Analyzing your question...',
            'Understanding your needs...',
            'Processing your request...',
        ],
    },
    searching: {
        texts: [
            'Searching products...',
            'Exploring our catalog...',
            'Finding relevant options...',
        ],
    },
    generating: {
        texts: [
            'Writing response...',
            'Crafting your answer...',
            'Preparing recommendations...',
        ],
    },
    product_recommendation: {
        texts: [
            'And now, describing that perfect product...',
            'Highlighting key features...',
            'Explaining why this fits...',
        ],
    },
    selecting_products: {
        texts: [
            'Finding the right product...',
            'Evaluating options...',
            'Comparing features...',
        ],
    },
    finalizing: {
        texts: [
            'Finalizing...',
            'Wrapping up...',
            'Almost done...',
        ],
    },
    awaiting_clarification: {
        texts: [
            'Waiting for your response...',
            'Ready for your input...',
            'Standing by...',
        ],
    },
    error: {
        texts: [
            'An error occurred',
            'Something went wrong',
            'Unable to complete',
        ],
    },
};

export interface SearchPipelineStatusIndicatorProps {
    status: string | null;
}

export const SearchPipelineStatusIndicator: React.FC<SearchPipelineStatusIndicatorProps> = ({ status }) => {
    const [variationIndex, setVariationIndex] = useState(0);
    const statusStartTimeRef = useRef<number | null>(null);
    const currentStatusRef = useRef<string | null>(null);

    // Reset variation when status changes
    useEffect(() => {
        if (currentStatusRef.current !== status) {
            currentStatusRef.current = status;
            statusStartTimeRef.current = Date.now();
            setVariationIndex(0);
        }
    }, [status]);

    // Rotate variations every 2 seconds
    useEffect(() => {
        if (!status) return;
        const config = statusConfig[status];
        if (!config || config.texts.length <= 1) return;

        const interval = setInterval(() => {
            setVariationIndex((prev) => (prev + 1) % config.texts.length);
        }, 2000);

        return () => clearInterval(interval);
    }, [status]);

    if (!status || status === 'idle' || status === 'done') return null;

    const config = statusConfig[status] || { texts: ['Processing...'] };
    const currentText = config.texts[variationIndex] || config.texts[0];

    return (
        <div
            className="omniguide-pipeline-status"
            role="status"
            aria-live="polite"
            aria-atomic="true"
            aria-label={currentText}
        >
            <span className="omniguide-pipeline-status__text">{currentText}</span>
        </div>
    );
};
