/**
 * Pure text transformation utilities.
 * No DOM dependencies — safe for Node.js and SSR.
 */

import removeMd from 'remove-markdown';

const MAX_SUMMARY_CHARS = 200;

/**
 * Clean raw markdown text by removing headings, TOC entries, and markdown syntax.
 * Returns a single collapsed line of plain text.
 */
export function cleanText(raw = ''): string {
    if (!raw) return '';

    const lines = raw.split('\n');
    const filtered: string[] = [];
    let inToc = false;

    for (const line of lines) {
        const trimmed = line.trim();
        if (!trimmed) continue;

        if (/^table of contents$/i.test(trimmed)) {
            inToc = true;
            continue;
        }

        if (/^toggle$/i.test(trimmed)) {
            continue;
        }

        if (inToc) {
            if (/^[*-]\s*\[.*]\(.*\)/i.test(trimmed)) {
                continue;
            }
            if (/^\*?\s*\[.*]\(.*\)/i.test(trimmed)) {
                continue;
            }
            if (/^#{1,6}\s*/.test(trimmed)) {
                inToc = false;
            } else {
                continue;
            }
        }

        if (/^#{1,6}\s*/.test(trimmed)) {
            continue;
        }

        filtered.push(trimmed);
    }

    let text = filtered.join(' ');
    text = removeMd(text, { listUnicodeChar: '', useImgAltText: true });
    text = text.replace(/\s+/g, ' ').trim();

    return text;
}

/**
 * Shorten text to a maximum character limit without breaking mid-word.
 */
export function shortenText(text: string, limit = MAX_SUMMARY_CHARS): string {
    if (!text) return '';
    if (text.length <= limit) return text;
    return text.slice(0, limit).trimEnd();
}

/**
 * Clean raw markdown and shorten it for use as a summary.
 */
export function transformSummary(rawSummary: string): string {
    return shortenText(cleanText(rawSummary));
}

/**
 * Extract all SKUs from markdown content.
 * Supports multiple formats: markdown links with (SKU: XX), product shortcodes, etc.
 */
export function extractSkusFromMarkdown(content: string): string[] {
    if (!content) return [];

    const skus = new Set<string>();
    let match: RegExpExecArray | null;

    // Format 0: Extract SKU from any markdown link [text](url) where text contains (SKU: XX)
    const markdownLinkRegex = /\[([^\]]+)\]\(([^)]+)\)/g;
    while ((match = markdownLinkRegex.exec(content)) !== null) {
        const linkText = match[1] ?? '';
        const skuMatch = linkText.match(/\(SKU:\s*(\d+)\)|SKU:\s*(\d+)/i);
        if (skuMatch) {
            const sku = skuMatch[1] ?? skuMatch[2] ?? '';
            if (sku) skus.add(sku);
        }
    }

    // Product shortcode format 1: [product sku="SKU"]Product Name[/product]
    const format1Regex = /\[product\s+sku=['"]([^'"]+)['"]\][^[]+\[\/product\]/g;
    while ((match = format1Regex.exec(content)) !== null) {
        if (match[1]) skus.add(match[1]);
    }

    // Product shortcode format 2: [Product Name](sku="SKU")
    const format2Regex = /\[[^\]]+\]\(sku=['"]([^'"]+)['"]\)/g;
    while ((match = format2Regex.exec(content)) !== null) {
        if (match[1]) skus.add(match[1]);
    }

    // Product shortcode format 3: [Product Name SKU: XX]
    const format3Regex = /\[.+?\s+SKU:\s*(\d+)\]/g;
    while ((match = format3Regex.exec(content)) !== null) {
        if (match[1]) skus.add(match[1]);
    }

    return Array.from(skus);
}
