/**
 * Page Context — captures referrer, UTM parameters, and user agent once at page load.
 *
 * Singleton: the first call to `capturePageContext()` snapshots the values.
 * Subsequent calls (including after SPA navigation) return the same snapshot.
 * SSR-safe — returns empty context when `document`/`navigator` are unavailable.
 */

// ── Types ──────────────────────────────────────────────────────────

export interface PageContext {
  referrer: string;
  user_agent: string;
  utm_source?: string;
  utm_medium?: string;
  utm_campaign?: string;
  utm_term?: string;
  utm_content?: string;
}

// ── Singleton ──────────────────────────────────────────────────────

let captured: PageContext | null = null;

const UTM_KEYS = ['utm_source', 'utm_medium', 'utm_campaign', 'utm_term', 'utm_content'] as const;

/**
 * Strip query string and fragment from a URL to avoid leaking sensitive
 * params (PHPSESSID, OAuth tokens, reset keys, etc.) in analytics payloads.
 * Returns origin + pathname only, or the original string on parse failure.
 */
function sanitizeReferrer(raw: string): string {
  if (!raw) return '';
  try {
    const url = new URL(raw);
    return url.origin + url.pathname;
  } catch {
    return raw;
  }
}

/**
 * Capture page context (referrer, UTM params, user agent).
 * Safe to call multiple times — only the first call captures; subsequent calls are no-ops.
 * Returns the captured context.
 */
export function capturePageContext(): PageContext {
  if (captured) return captured;

  if (typeof document === 'undefined' || typeof navigator === 'undefined') {
    captured = { referrer: '', user_agent: '' };
    return captured;
  }

  const ctx: PageContext = {
    referrer: sanitizeReferrer(document.referrer),
    user_agent: navigator.userAgent || '',
  };

  try {
    const params = new URLSearchParams(window.location.search);
    for (const key of UTM_KEYS) {
      const value = params.get(key);
      if (value) {
        ctx[key] = value;
      }
    }
  } catch {
    // URLSearchParams unavailable or location not accessible — skip UTM
  }

  captured = ctx;
  return captured;
}

/**
 * Get the previously captured page context.
 * If `capturePageContext()` hasn't been called yet, calls it automatically.
 */
export function getPageContext(): PageContext {
  return captured ?? capturePageContext();
}

/**
 * Reset captured context (for testing only).
 * @internal
 */
export function _resetPageContext(): void {
  captured = null;
}
