/**
 * REST response validation — validates NORMALIZED shapes (post-normalize()).
 *
 * Schema names use protocol prefix (Rest*) to distinguish from WS schemas
 * in core/src/schemas.ts.
 *
 * For WS message validation (raw server payloads, inline), see core/src/schemas.ts.
 */

import { z } from 'zod';

// ── Session ─────────────────────────────────────────────────────

export const RestSessionResponseSchema = z.object({
  sessionId: z.string(),
  welcomeText: z.string().optional(),
  seedQuestions: z.array(z.string()).optional(),
  aiDisabled: z.boolean().optional(),
  disabledReason: z.string().nullable().optional(),
});

// ── Questions ───────────────────────────────────────────────────

export const RestDiscoveryAnswerSchema = z.object({
  id: z.string(),
  text: z.string(),
});

export const RestDiscoveryQuestionSchema = z.object({
  id: z.string(),
  question: z.string(),
  answers: z.array(RestDiscoveryAnswerSchema),
  allowOther: z.boolean().optional(),
  productTypeId: z.number().optional(),
});

export const RestQuestionsResponseSchema = z.array(RestDiscoveryQuestionSchema);

// ── Feedback ────────────────────────────────────────────────────

export const RestFeedbackResponseSchema = z.object({
  success: z.boolean(),
  feedbackId: z.string(),
  message: z.string().optional(),
});
