/**
 * Storage utilities for Omniguide SDK
 *
 * Provides storage abstraction to avoid direct localStorage access.
 * This allows the SDK to work in environments without localStorage
 * and enables testing with mock storage.
 */

import type { StorageAdapter, AnsweredIntent } from './types.js';
import { logger } from './logger.js';

/**
 * Default storage keys
 */
export const DEFAULT_STORAGE_KEYS = {
  sessionId: 'omniguide_session_id',
  answeredIntents: 'omniguideAnsweredIntents',
} as const;

/**
 * Browser localStorage adapter
 */
export class LocalStorageAdapter implements StorageAdapter {
  private available: boolean;

  constructor() {
    this.available = this.checkAvailability();
  }

  private checkAvailability(): boolean {
    try {
      const testKey = '__omniguide_storage_test__';
      localStorage.setItem(testKey, 'test');
      localStorage.removeItem(testKey);
      return true;
    } catch {
      return false;
    }
  }

  getItem(key: string): string | null {
    if (!this.available) {
      return null;
    }
    try {
      return localStorage.getItem(key);
    } catch (error) {
      logger.warn('Failed to read from localStorage:', error);
      return null;
    }
  }

  setItem(key: string, value: string): void {
    if (!this.available) {
      return;
    }
    try {
      localStorage.setItem(key, value);
    } catch (error) {
      logger.warn('Failed to write to localStorage:', error);
    }
  }

  removeItem(key: string): void {
    if (!this.available) {
      return;
    }
    try {
      localStorage.removeItem(key);
    } catch (error) {
      logger.warn('Failed to remove from localStorage:', error);
    }
  }
}

/**
 * In-memory storage adapter (for testing or fallback)
 */
export class MemoryStorageAdapter implements StorageAdapter {
  private store: Map<string, string> = new Map();

  getItem(key: string): string | null {
    return this.store.get(key) ?? null;
  }

  setItem(key: string, value: string): void {
    this.store.set(key, value);
  }

  removeItem(key: string): void {
    this.store.delete(key);
  }

  clear(): void {
    this.store.clear();
  }
}

/**
 * Answered intents storage manager
 */
export class AnsweredIntentsStorage {
  private storage: StorageAdapter;
  private storageKey: string;

  constructor(storage: StorageAdapter, storageKey = DEFAULT_STORAGE_KEYS.answeredIntents) {
    this.storage = storage;
    this.storageKey = storageKey;
  }

  /**
   * Load answered intents from storage
   */
  load(productTypeId?: number): Record<string, AnsweredIntent> {
    try {
      const stored = this.storage.getItem(this.storageKey);
      const intents: Record<string, AnsweredIntent> = stored ? JSON.parse(stored) : {};

      if (productTypeId === undefined) {
        return intents;
      }

      // Filter by product type ID
      const filtered: Record<string, AnsweredIntent> = {};
      for (const [key, value] of Object.entries(intents)) {
        if (value.productTypeId === productTypeId || value.productTypeId === undefined) {
          filtered[key] = value;
        }
      }
      return filtered;
    } catch (error) {
      logger.warn('Failed to load answered intents:', error);
      return {};
    }
  }

  /**
   * Save answered intents to storage
   */
  save(intents: Record<string, AnsweredIntent>): void {
    try {
      this.storage.setItem(this.storageKey, JSON.stringify(intents));
    } catch (error) {
      logger.warn('Failed to save answered intents:', error);
    }
  }

  /**
   * Add or update an answered intent
   */
  upsert(intent: AnsweredIntent): void {
    const intents = this.load();
    intents[intent.questionId] = intent;
    this.save(intents);
  }

  /**
   * Remove specific question answers
   */
  remove(questionIds: string[]): void {
    const intents = this.load();
    for (const id of questionIds) {
      delete intents[id];
    }
    this.save(intents);
  }

  /**
   * Clear all answered intents
   */
  clear(): void {
    this.storage.removeItem(this.storageKey);
  }

  /**
   * Convert to API format (numeric IDs without prefixes)
   */
  toApiFormat(productTypeId?: number): Record<string, { answer_id: number | string; answer_text: string }> {
    const intents = this.load(productTypeId);
    const apiFormat: Record<string, { answer_id: number | string; answer_text: string }> = {};

    for (const [questionId, answer] of Object.entries(intents)) {
      // Strip prefix from question IDs for API compatibility
      const questionKey = questionId
        .replace(/^discovery_/, '')
        .replace(/^dynamic_/, '')
        .replace(/^intent_/, '');

      // Parse answer ID
      const answerIdStr = String(answer.answerId);
      const numericAnswerId = parseInt(
        answerIdStr
          .replace(/^discovery_/, '')
          .replace(/^dynamic_/, '')
          .replace(/^intent_/, ''),
        10
      );

      apiFormat[questionKey] = {
        answer_id: isNaN(numericAnswerId) ? answer.answerId : numericAnswerId,
        answer_text: answer.answerText,
      };
    }

    return apiFormat;
  }
}

/**
 * Session storage manager
 */
export class SessionStorage {
  private storage: StorageAdapter;
  private storageKey: string;
  private sessionId: string | null = null;

  constructor(storage: StorageAdapter, storageKey = DEFAULT_STORAGE_KEYS.sessionId) {
    this.storage = storage;
    this.storageKey = storageKey;
    this.sessionId = this.storage.getItem(this.storageKey);
  }

  /**
   * Get current session ID
   */
  get(): string | null {
    return this.sessionId;
  }

  /**
   * Update session ID (called when server provides canonical ID)
   */
  update(newSessionId: string): void {
    if (!newSessionId || typeof newSessionId !== 'string') {
      return;
    }

    if (this.sessionId !== newSessionId) {
      this.sessionId = newSessionId;
      this.storage.setItem(this.storageKey, newSessionId);
    }
  }

  /**
   * Clear session ID
   */
  clear(): void {
    this.sessionId = null;
    this.storage.removeItem(this.storageKey);
  }
}

/**
 * Check if a question ID has a discovery prefix
 */
export function isDiscoveryQuestionId(questionId: string | number): boolean {
  const idStr = String(questionId);
  return idStr.startsWith('discovery_') || idStr.startsWith('dynamic_');
}

/**
 * Add discovery prefix to an ID
 */
export function toDiscoveryId(id: string | number): string {
  const idStr = String(id);
  if (idStr.startsWith('discovery_') || idStr.startsWith('dynamic_') || idStr.startsWith('intent_')) {
    return idStr;
  }
  return `discovery_${id}`;
}
