/**
 * useProductWebSocket
 *
 * Manages WebSocket connection for product fit evaluation.
 * Supports conversational flow where questions are received one at a time.
 * Platform-agnostic — hydration is injected via options.
 */

import { useState, useRef, useCallback, useEffect } from 'react';
import { FLOW_STATES, logger, normalizeQuestions } from '@swiftotter/omniguide-core';
import type { FlowState } from '@swiftotter/omniguide-core';
import { useStatusMessage } from './useStatusMessage.js';
import { useDiscoveryAnswerStorage } from './useDiscoveryAnswerStorage.js';
import type { DiscoveryAnswerStorageAdapter } from './useDiscoveryAnswerStorage.js';

// =========================================
// Types
// =========================================

export interface ProductHydration {
  hydrateCurrentProduct: (product: Record<string, unknown>) => Promise<Record<string, unknown> | null>;
  hydrateAlternativeProduct: (product: Record<string, unknown>) => Promise<Record<string, unknown> | null>;
}

export interface ProductWebSocketFactory {
  create: (config: {
    onMessage: (msg: Record<string, unknown>) => void;
    onStatusChange: (status: string) => void;
    onError: (err: Error) => void;
  }) => ProductWebSocketInstance;
}

export interface ProductWebSocketInstance {
  connect: () => Promise<void>;
  disconnect: () => void;
  isConnected: () => boolean;
  sendStartMessage: (sku: string, firstAnswer?: Record<string, unknown> | null) => void;
  sendResumeMessage: (sku: string, answeredIntents: Record<string, unknown>) => void;
  sendAnswerMessage: (questionId: string, answerId: string | null, answerText: string) => void;
}

export interface UseProductWebSocketOptions {
  /** Hydration functions for enriching products with platform data */
  hydration: ProductHydration;
  /** Factory to create WebSocket instances */
  wsFactory: ProductWebSocketFactory;
  /** Storage adapter for persisting answers */
  storageAdapter: DiscoveryAnswerStorageAdapter;
  /** Product type ID for filtering stored answers */
  productTypeId?: number | string | null;
}

export const PRODUCT_STATUS_MESSAGES: Record<string, string> = {
  analyzing_preferences: 'Analyzing your preferences...',
  evaluating_fit: 'Evaluating product fit...',
  finding_alternatives: 'Finding alternatives...',
  generating_insights: 'Generating insights...',
  finalizing: 'Finalizing evaluation...',
  processing: 'Processing...',
};

// =========================================
// Utility
// =========================================

function withTimeout<T>(promise: Promise<T>, timeoutMs: number, fallbackValue: T): Promise<T> {
  return Promise.race([
    promise,
    new Promise<T>((resolve) => {
      setTimeout(() => resolve(fallbackValue), timeoutMs);
    }),
  ]);
}

// =========================================
// Hook
// =========================================

export function useProductWebSocket({
  hydration,
  wsFactory,
  storageAdapter,
  productTypeId = null,
}: UseProductWebSocketOptions) {
  const [connectionStatus, setConnectionStatus] = useState('disconnected');

  // Conversational flow state
  const [flowState, setFlowState] = useState<FlowState>(FLOW_STATES.IDLE);
  const [currentQuestion, setCurrentQuestion] = useState<Record<string, unknown> | null>(null);
  const [questionNumber, setQuestionNumber] = useState(0);
  const [answeredQuestions, setAnsweredQuestions] = useState<Array<{ question: unknown; answer: { answer_id: string | null; answer: string } }>>([]);

  // Results state
  const [fitResult, setFitResult] = useState<Record<string, unknown> | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<Error | null>(null);

  // Status message state
  const [processingStatus, setProcessingStatus] = useState<string | null>(null);

  // "Other" answer state
  const [otherValidationError, setOtherValidationError] = useState<{ message: string } | null>(null);
  const [clarificationPrompt, setClarificationPrompt] = useState<string | null>(null);
  const [isOtherProcessing, setIsOtherProcessing] = useState(false);

  const wsRef = useRef<ProductWebSocketInstance | null>(null);
  const requestInProgressRef = useRef(false);
  const skuRef = useRef<string | null>(null);
  const questionNumberRef = useRef(questionNumber);

  // Shared hooks
  const { saveAnswer, restoreFromStorage, hasStoredSession, clearStorage } = useDiscoveryAnswerStorage(storageAdapter, productTypeId);
  const { getStatusMessage } = useStatusMessage(processingStatus, PRODUCT_STATUS_MESSAGES);

  useEffect(() => {
    questionNumberRef.current = questionNumber;
  }, [questionNumber]);

  useEffect(() => {
    return () => {
      if (wsRef.current) {
        wsRef.current.disconnect();
        wsRef.current = null;
      }
    };
  }, []);

  const disconnectWebSocket = useCallback(() => {
    if (wsRef.current) {
      wsRef.current.disconnect();
      wsRef.current = null;
      setConnectionStatus('disconnected');
    }
  }, []);

  const hydrateProducts = useCallback(async (result: Record<string, unknown>) => {
    const HYDRATION_TIMEOUT_MS = 5000;
    const hydrationPromises: Promise<{ type: string; data: unknown }>[] = [];

    if (result['currentProduct']) {
      const product = result['currentProduct'] as Record<string, unknown>;
      const hydrationPromise = hydration.hydrateCurrentProduct(product)
        .then((hydrated) => ({ type: 'currentProduct', data: hydrated }))
        .catch(() => ({ type: 'currentProduct', data: product }));
      const fallback = { type: 'currentProduct', data: product };
      hydrationPromises.push(withTimeout(hydrationPromise, HYDRATION_TIMEOUT_MS, fallback));
    }

    if (result['alternative']) {
      const alternative = result['alternative'] as Record<string, unknown>;
      const hydrationPromise = hydration.hydrateAlternativeProduct(alternative)
        .then((hydrated) => ({ type: 'alternative', data: hydrated }))
        .catch(() => ({ type: 'alternative', data: alternative }));
      const fallback = { type: 'alternative', data: alternative };
      hydrationPromises.push(withTimeout(hydrationPromise, HYDRATION_TIMEOUT_MS, fallback));
    }

    if (hydrationPromises.length > 0) {
      setProcessingStatus('finalizing');
      try {
        const results = await Promise.all(hydrationPromises);
        const updates: Record<string, unknown> = {};
        results.forEach(({ type, data }) => {
          updates[type] = data;
        });
        return updates;
      } catch {
        return {};
      }
    }
    return {};
  }, [hydration]);

  const createMessageHandler = useCallback((msg: Record<string, unknown>) => {
    switch (msg['type']) {
      case 'question': {
        const rawQuestion = msg['question'] as Record<string, unknown>;
        // Normalize WebSocket question to match DiscoveryQuestion shape
        // (backend sends question_id/question_text/answer_text, components expect id/question/text)
        const normalized = normalizeQuestions({ questions: [rawQuestion] } as Parameters<typeof normalizeQuestions>[0]);
        setCurrentQuestion((normalized[0] as unknown as Record<string, unknown>) ?? rawQuestion);
        setQuestionNumber((msg['question_number'] as number) || questionNumberRef.current + 1);
        setFlowState(FLOW_STATES.QUESTIONING);
        setIsLoading(false);
        break;
      }

      case 'resumed': {
        const answeredCount = (msg['answered_count'] as number) || 0;
        setQuestionNumber(answeredCount);
        break;
      }

      case 'status': {
        const status = msg['status'] as string;
        setProcessingStatus(status);
        if (status === 'questions_complete') {
          setFlowState(FLOW_STATES.LOADING_RESULTS);
          setIsLoading(true);
          setCurrentQuestion(null);
        } else if (status === 'processing' || status === 'evaluating_fit') {
          setIsLoading(true);
        }
        break;
      }

      case 'fit_evaluation': {
        const result: Record<string, unknown> = {
          currentProduct: msg['current_product'],
          fitEvaluation: msg['fit_evaluation'],
          fitExplanation: msg['fit_explanation'],
          alternative: msg['alternative'],
        };

        setFitResult(result);
        disconnectWebSocket();

        hydrateProducts(result)
          .then((updates) => {
            if (Object.keys(updates).length > 0) {
              setFitResult((prev) => prev ? { ...prev, ...updates } : updates);
            }
            setIsLoading(false);
            setProcessingStatus(null);
            setError(null);
            setFlowState(FLOW_STATES.COMPLETE);
            requestInProgressRef.current = false;
          })
          .catch(() => {
            setIsLoading(false);
            setProcessingStatus(null);
            setError(null);
            setFlowState(FLOW_STATES.COMPLETE);
            requestInProgressRef.current = false;
          });
        break;
      }

      case 'answer_response': {
        setIsOtherProcessing(false);
        if (msg['validation_failed']) {
          setOtherValidationError({ message: (msg['error_message'] as string) || 'Invalid answer. Please try again.' });
          setIsLoading(false);
        } else if (msg['needs_clarification']) {
          setClarificationPrompt((msg['clarification_prompt'] as string) || 'Please provide more details.');
          setIsLoading(false);
        } else if (msg['has_next_question']) {
          setOtherValidationError(null);
          setClarificationPrompt(null);
        } else if (msg['is_terminal']) {
          setOtherValidationError(null);
          setClarificationPrompt(null);
          setFlowState(FLOW_STATES.LOADING_RESULTS);
          setIsLoading(true);
          setCurrentQuestion(null);
        }
        break;
      }

      case 'done':
        setIsLoading(false);
        setProcessingStatus(null);
        requestInProgressRef.current = false;
        disconnectWebSocket();
        break;

      case 'error': {
        const rawError = (msg['content'] as string) || 'Unknown error';
        logger.error('Product WebSocket error:', rawError);
        setError(new Error('We encountered an error while processing your request. Please try again.'));
        setIsLoading(false);
        setProcessingStatus(null);
        setFlowState(FLOW_STATES.ERROR);
        requestInProgressRef.current = false;
        disconnectWebSocket();
        break;
      }
    }
  }, [disconnectWebSocket, hydrateProducts]);

  const connectWebSocket = useCallback(async () => {
    disconnectWebSocket();

    const ws = wsFactory.create({
      onMessage: createMessageHandler,
      onStatusChange: setConnectionStatus,
      onError: (err: Error) => {
        logger.error('Product WebSocket connection error:', err.message);
        setError(err);
        setIsLoading(false);
        setProcessingStatus(null);
        setFlowState(FLOW_STATES.ERROR);
        requestInProgressRef.current = false;
        disconnectWebSocket();
      },
    });

    wsRef.current = ws;
    await ws.connect();
    return ws;
  }, [wsFactory, createMessageHandler, disconnectWebSocket]);

  const resetForNewRequest = useCallback(() => {
    setIsLoading(true);
    setError(null);
    setFitResult(null);
    setProcessingStatus('analyzing_preferences');
    setFlowState(FLOW_STATES.CONNECTING);
  }, []);

  const startConversation = useCallback(async (
    sku: string,
    firstAnswer: { questionId: string; answerId: string | null; answerText: string } | null = null,
    firstQuestion: Record<string, unknown> | null = null,
  ) => {
    if (requestInProgressRef.current) return;
    requestInProgressRef.current = true;
    skuRef.current = sku;

    resetForNewRequest();

    if (firstAnswer && firstQuestion) {
      setAnsweredQuestions([{
        question: firstQuestion,
        answer: { answer_id: firstAnswer.answerId, answer: firstAnswer.answerText },
      }]);
      setQuestionNumber(1);
      saveAnswer(firstAnswer.questionId, firstAnswer.answerId, firstAnswer.answerText, firstAnswer.answerId === null, firstQuestion);
    } else {
      setAnsweredQuestions([]);
      setQuestionNumber(0);
    }

    try {
      const ws = await connectWebSocket();
      ws.sendStartMessage(sku, firstAnswer);
    } catch (err) {
      logger.error('Product WebSocket startConversation failed:', err instanceof Error ? err.message : String(err));
      setError(err instanceof Error ? err : new Error(String(err)));
      setIsLoading(false);
      setProcessingStatus(null);
      setFlowState(FLOW_STATES.ERROR);
      requestInProgressRef.current = false;
      disconnectWebSocket();
    }
  }, [connectWebSocket, disconnectWebSocket, resetForNewRequest, saveAnswer]);

  const resumeSession = useCallback(async (sku: string) => {
    const answeredIntents = storageAdapter.getForApi(productTypeId);
    if (Object.keys(answeredIntents).length === 0) return false;
    if (requestInProgressRef.current) return false;

    requestInProgressRef.current = true;
    skuRef.current = sku;

    const restoredAnswers = restoreFromStorage();
    setAnsweredQuestions(restoredAnswers);
    setQuestionNumber(Object.keys(answeredIntents).length);
    resetForNewRequest();

    try {
      const ws = await connectWebSocket();
      ws.sendResumeMessage(sku, answeredIntents);
      return true;
    } catch (err) {
      logger.error('Product WebSocket resumeSession failed:', err instanceof Error ? err.message : String(err));
      setError(err instanceof Error ? err : new Error(String(err)));
      setIsLoading(false);
      setProcessingStatus(null);
      setFlowState(FLOW_STATES.ERROR);
      requestInProgressRef.current = false;
      disconnectWebSocket();
      return false;
    }
  }, [connectWebSocket, disconnectWebSocket, resetForNewRequest, restoreFromStorage, storageAdapter, productTypeId]);

  const submitAnswer = useCallback((questionId: string, answerId: string | null, answerText: string, question: Record<string, unknown>) => {
    if (!wsRef.current || !wsRef.current.isConnected()) return;

    setAnsweredQuestions((prev) => [...prev, {
      question,
      answer: { answer_id: answerId, answer: answerText },
    }]);

    saveAnswer(questionId, answerId, answerText, false, question);
    setIsLoading(true);
    setCurrentQuestion(null);
    wsRef.current.sendAnswerMessage(questionId, answerId, answerText);
  }, [saveAnswer]);

  const submitOtherAnswer = useCallback((questionId: string, answerText: string, question: Record<string, unknown>) => {
    if (!wsRef.current || !wsRef.current.isConnected()) return;

    setOtherValidationError(null);
    setIsOtherProcessing(true);
    setIsLoading(true);

    setAnsweredQuestions((prev) => [...prev, {
      question,
      answer: { answer_id: null, answer: answerText },
    }]);

    saveAnswer(questionId, null, answerText, true, question);
    wsRef.current.sendAnswerMessage(questionId, null, answerText);
  }, [saveAnswer]);

  const clearOtherError = useCallback(() => {
    setOtherValidationError(null);
  }, []);

  const resetConversation = useCallback(() => {
    disconnectWebSocket();
    clearStorage();
    setFlowState(FLOW_STATES.IDLE);
    setCurrentQuestion(null);
    setQuestionNumber(0);
    setAnsweredQuestions([]);
    setFitResult(null);
    setIsLoading(false);
    setError(null);
    setProcessingStatus(null);
    setOtherValidationError(null);
    setClarificationPrompt(null);
    setIsOtherProcessing(false);
    requestInProgressRef.current = false;
  }, [disconnectWebSocket, clearStorage]);

  const disconnect = useCallback(() => {
    disconnectWebSocket();
  }, [disconnectWebSocket]);

  return {
    connectionStatus,
    flowState,
    currentQuestion,
    questionNumber,
    answeredQuestions,
    fitResult,
    isLoading,
    error,
    processingStatus,
    otherValidationError,
    clarificationPrompt,
    isOtherProcessing,
    getStatusMessage,
    startConversation,
    resumeSession,
    submitAnswer,
    submitOtherAnswer,
    clearOtherError,
    resetConversation,
    disconnect,
    hasStoredSession,
  };
}
