import React from 'react';

export interface SearchConnectionErrorProps {
    onRetry?: () => void;
    isMobile?: boolean;
}

/**
 * Connection error state shown when the WebSocket can't connect.
 * Replaces SearchEmptyState when connectionStatus === 'disconnected' and no messages exist.
 */
export const SearchConnectionError: React.FC<SearchConnectionErrorProps> = ({
    onRetry,
    isMobile = false,
}) => {
    return (
        <div
            className={`omniguide-connection-error ${isMobile ? 'omniguide-connection-error--mobile' : ''}`}
            role="alert"
        >
            <div className="omniguide-connection-error__icon">
                <svg width="24" height="24" viewBox="0 0 20 20" fill="currentColor" aria-hidden="true">
                    <path
                        fillRule="evenodd"
                        d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 2.98-1.742 2.98H4.42c-1.53 0-2.493-1.646-1.743-2.98l5.58-9.92zM11 13a1 1 0 11-2 0 1 1 0 012 0zm-1-8a1 1 0 00-1 1v3a1 1 0 002 0V6a1 1 0 00-1-1z"
                        clipRule="evenodd"
                    />
                </svg>
            </div>
            <h3 className="omniguide-connection-error__title">Unable to connect</h3>
            <p className="omniguide-connection-error__text">
                We couldn&apos;t reach the assistant. Please check your connection and try again.
            </p>
            {onRetry && (
                <button
                    type="button"
                    className="omniguide-connection-error__retry-btn"
                    onClick={onRetry}
                >
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
                        <polyline points="23 4 23 10 17 10" />
                        <path d="M20.49 15a9 9 0 1 1-2.12-9.36L23 10" />
                    </svg>
                    <span>Try Again</span>
                </button>
            )}
        </div>
    );
};
