/**
 * Product WebSocket for product fit evaluation
 *
 * Extends BaseWebSocket with product-specific functionality:
 * - Start/resume questionnaire flow
 * - Answer submission
 * - Fit evaluation requests
 */

import { BaseWebSocket, getWebSocketBaseUrl } from '../websocket.js';
import type { WebSocketConfig, WebSocketMessage } from '../types.js';

export interface ProductWebSocketConfig extends Omit<WebSocketConfig, 'logPrefix'> {
  /** Base URL for the Omniguide API */
  apiBaseUrl: string;
}

export interface FirstAnswer {
  questionId: string;
  answerId: string | null;
  answerText: string;
}

export interface DiscoveryAnswers {
  [questionId: string]: {
    answer_id: string | number;
    answer_text: string;
  };
}

/**
 * WebSocket manager for product fit evaluation
 */
export class ProductWebSocket extends BaseWebSocket {
  private apiBaseUrl: string;

  constructor(config: ProductWebSocketConfig) {
    super({
      ...config,
      // Product-specific settings
      enableHeartbeat: true,
      heartbeatIntervalMs: 5000,
      maxReconnectAttempts: 3,
      maxBackoffDelay: 10000,
      logPrefix: '[ProductWebSocket]',
    });

    this.apiBaseUrl = config.apiBaseUrl;
  }

  /**
   * Get WebSocket URL for product recommendations
   */
  protected getWebSocketUrl(): string {
    const baseUrl = getWebSocketBaseUrl(this.apiBaseUrl);
    return `${baseUrl}/ws/product-recommendations/${this.sessionId}`;
  }

  /**
   * Handle product-specific messages
   */
  protected override handleMessage(msg: WebSocketMessage): void {
    this.onMessage(msg);
  }

  /**
   * Send start message to begin conversational flow
   * Note: start only accepts first_answer, not discovery_answers.
   * Use resume for multiple pre-answered questions.
   */
  sendStartMessage(sku: string, firstAnswer?: FirstAnswer): void {
    const message: Record<string, unknown> = {
      type: 'start',
      sku,
    };

    if (firstAnswer) {
      message['first_answer'] = {
        question_id: firstAnswer.questionId,
        answer_id: firstAnswer.answerId,
        answer_text: firstAnswer.answerText,
      };
    }

    this.send(message);
  }

  /**
   * Send resume message to continue from a stored session
   */
  sendResumeMessage(sku: string, discoveryAnswers: DiscoveryAnswers = {}): void {
    this.send({
      type: 'resume',
      sku,
      discovery_answers: discoveryAnswers,
    });
  }

  /**
   * Send answer for subsequent questions
   */
  sendAnswerMessage(questionId: string, answerId: string | null, answerText: string): void {
    if (!this.isConnected() || !this.ws) {
      throw new Error('WebSocket not connected');
    }

    // This message doesn't use send() because it doesn't need website_code/current_page
    this.ws.send(
      JSON.stringify({
        type: 'answer',
        question_id: questionId,
        answer_id: answerId,
        answer_text: answerText,
      })
    );
  }

  /**
   * Send fit evaluation request (legacy - for batch submission)
   */
  sendFitEvaluationRequest(
    sku: string,
    discoveryAnswers: DiscoveryAnswers,
    options: { metadataFilters?: Record<string, unknown> } = {}
  ): void {
    this.send({
      type: 'evaluate_fit',
      sku,
      discovery_answers: discoveryAnswers,
      metadata_filters: options.metadataFilters ?? {},
    });
  }
}
