import React, { useLayoutEffect, useRef, useState } from 'react';
import { clearPreviewApiUrl, getPreviewApiUrl } from '@swiftotter/omniguide-core';

const BANNER_ID = 'omniguide-preview-banner';

/**
 * Floating banner that indicates the SDK is running in preview mode
 * (pointing at a staging API). Shows the staging URL and a deactivate button.
 *
 * - Adds padding-top to <body> so content isn't hidden behind the banner.
 * - X button dismisses the banner for the current page load (restores on reload).
 * - Deactivate button clears localStorage and reloads (exits preview mode).
 */
export function PreviewBanner(): JSX.Element | null {
  const [dismissed, setDismissed] = useState(false);
  const bannerRef = useRef<HTMLDivElement>(null);

  const previewUrl = getPreviewApiUrl();

  // Extract hostname for display
  let displayHost = previewUrl ?? '';
  try {
    displayHost = new URL(previewUrl!).hostname;
  } catch {
    /* show raw value */
  }

  // Deduplicate: if another OmniguideProvider already rendered a banner, skip
  const isDuplicate =
    typeof document !== 'undefined' &&
    document.getElementById(BANNER_ID) !== null &&
    document.getElementById(BANNER_ID) !== bannerRef.current;

  // Apply/remove body padding synchronously before paint
  useLayoutEffect(() => {
    if (dismissed || isDuplicate || !bannerRef.current) {
      document.body.style.paddingTop = '';
      return;
    }
    const height = bannerRef.current.getBoundingClientRect().height;
    document.body.style.paddingTop = `${height}px`;
    return () => { document.body.style.paddingTop = ''; };
  }, [dismissed, isDuplicate]);

  if (dismissed || isDuplicate) return null;

  const handleDeactivate = () => {
    clearPreviewApiUrl();
    window.location.reload();
  };

  const handleDismiss = () => {
    setDismissed(true);
  };

  return (
    <div
      id={BANNER_ID}
      ref={bannerRef}
      style={{
        position: 'fixed',
        top: 0,
        left: 0,
        right: 0,
        zIndex: 99999,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        gap: '10px',
        padding: '8px 40px 8px 16px',
        backgroundColor: '#f59e0b',
        color: '#000',
        fontSize: '13px',
        fontFamily: 'system-ui, -apple-system, sans-serif',
        fontWeight: 600,
        boxShadow: '0 2px 8px rgba(0,0,0,0.15)',
      }}
    >
      <span>PREVIEW MODE: {displayHost}</span>
      <button
        onClick={handleDeactivate}
        style={{
          padding: '3px 10px',
          fontSize: '12px',
          fontWeight: 600,
          backgroundColor: '#000',
          color: '#f59e0b',
          border: 'none',
          borderRadius: '4px',
          cursor: 'pointer',
        }}
      >
        Deactivate
      </button>
      <button
        onClick={handleDismiss}
        aria-label="Dismiss preview banner"
        style={{
          position: 'absolute',
          right: '10px',
          top: '50%',
          transform: 'translateY(-50%)',
          padding: '0',
          width: '20px',
          height: '20px',
          lineHeight: '20px',
          fontSize: '16px',
          fontWeight: 700,
          backgroundColor: 'transparent',
          color: '#000',
          border: 'none',
          cursor: 'pointer',
          opacity: 0.6,
        }}
      >
        ✕
      </button>
    </div>
  );
}
