/**
 * QuestionnaireTeaser — Collapsed preview wrapper for questionnaires.
 *
 * Shows a headline + CTA button with a faded/truncated preview of the
 * questionnaire content. Clicking expands to reveal the full questionnaire
 * with a smooth animation.
 *
 * Config-gated: only rendered when `features.questionnaireTeaser.categoryGuide`
 * or `features.questionnaireTeaser.productFit` is true.
 *
 * Designed as a standalone file for easy code-splitting if needed.
 */

import React, { useState, useEffect, useRef, useCallback, type ReactNode } from 'react';

// ── Types ──────────────────────────────────────────────────────────

export interface QuestionnaireTeaserProps {
  /** Content to show inside the teaser (the actual questionnaire) */
  children: ReactNode;
  /** Headline text shown in the collapsed header */
  headline?: string;
  /** CTA button label */
  ctaLabel?: string;
  /**
   * CSS class prefix for the teaser wrapper. Use to scope styles
   * per feature: 'omniguide-cr' (category) or 'omniguide-pr' (product).
   */
  classPrefix?: string;
  /** Callback when the teaser is expanded */
  onExpand?: () => void;
}

// ── Arrow icon (inline SVG) ────────────────────────────────────────

function ArrowIcon(): JSX.Element {
  return (
    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
      <path
        d="M5 12H19M19 12L12 5M19 12L12 19"
        stroke="currentColor"
        strokeWidth="2.5"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

// ── Component ──────────────────────────────────────────────────────

export function QuestionnaireTeaser({
  children,
  headline = 'Answer a couple of brief questions, and we\u2019ll build you a tailored buying guide.',
  ctaLabel = 'Start',
  classPrefix = 'omniguide-cr',
  onExpand,
}: QuestionnaireTeaserProps): JSX.Element {
  const base = `${classPrefix}-questionnaire-teaser`;

  const [expanded, setExpanded] = useState(false);
  const headerRef = useRef<HTMLDivElement>(null);
  const [headerHeight, setHeaderHeight] = useState<number | undefined>(undefined);

  // Measure header height via ResizeObserver for smooth max-height animation.
  // Guards against scrollHeight === 0 (element hidden by :has() CSS during loading).
  // Falls back to debounced window resize when ResizeObserver is unavailable.
  useEffect(() => {
    if (expanded) return;

    const el = headerRef.current;
    if (!el) return;

    const measure = () => {
      const height = el.scrollHeight;
      if (height > 0) {
        setHeaderHeight(height);
      }
    };

    measure();

    if (typeof ResizeObserver !== 'undefined') {
      const observer = new ResizeObserver(measure);
      observer.observe(el);
      return () => observer.disconnect();
    }

    // Fallback: debounced window resize for older browsers
    let timer: ReturnType<typeof setTimeout>;
    const onResize = () => {
      clearTimeout(timer);
      timer = setTimeout(measure, 150);
    };

    window.addEventListener('resize', onResize);
    return () => {
      clearTimeout(timer);
      window.removeEventListener('resize', onResize);
    };
  }, [expanded]);

  const handleExpand = useCallback(() => {
    setExpanded(true);
    onExpand?.();
  }, [onExpand]);

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === 'Enter' || e.key === ' ') {
        e.preventDefault();
        handleExpand();
      }
    },
    [handleExpand],
  );

  return (
    <div
      className={`${base}${expanded ? ` ${base}--expanded` : ''}`}
      onClick={!expanded ? handleExpand : undefined}
      role={!expanded ? 'button' : undefined}
      tabIndex={!expanded ? 0 : undefined}
      onKeyDown={!expanded ? handleKeyDown : undefined}
    >
      <div
        ref={headerRef}
        className={`${base}__header`}
        style={headerHeight ? { maxHeight: expanded ? 0 : headerHeight } : undefined}
      >
        <h2 className={`${base}__headline`}>{headline}</h2>
        <span className={`${base}__cta`}>
          {ctaLabel}
          <ArrowIcon />
        </span>
      </div>
      <div className={`${base}__body`}>{children}</div>
      <div className={`${base}__fade`} />
    </div>
  );
}
