/**
 * Session Service
 *
 * Single source of truth for Omniguide session management.
 * Handles getting, creating, and ensuring sessions exist.
 * Multiple concurrent callers share the same initialization promise.
 */

import type { StorageAdapter } from '../types.js';
import { API_ENDPOINTS } from '../constants.js';
import { getCurrentPage } from '../current-page.js';
import { setSessionId as setRegistrySessionId, clearSessionId as clearRegistrySessionId } from '../session-registry.js';
import { normalizeSessionResponse } from '../adapters/rest/normalize.js';
import { RestSessionResponseSchema } from '../adapters/rest/schemas.js';
import { SdkParseError } from '../errors.js';

export interface SessionServiceConfig {
  /** Omniguide backend base URL */
  apiBaseUrl: string;
  /** Website identifier (sent as website_code) */
  websiteId: string;
  /** Storage adapter for persisting session ID (defaults to localStorage) */
  storage?: StorageAdapter;
  /** Storage key for session ID */
  storageKey?: string;
}

const DEFAULT_STORAGE_KEY = 'omniguideSessionId';

export class SessionService {
  private apiBaseUrl: string;
  private websiteId: string;
  private storage: StorageAdapter;
  private storageKey: string;
  private initializationPromise: Promise<string> | null = null;

  constructor(config: SessionServiceConfig) {
    this.apiBaseUrl = config.apiBaseUrl.replace(/\/$/, '');
    this.websiteId = config.websiteId;
    this.storageKey = config.storageKey ?? DEFAULT_STORAGE_KEY;

    // Default to localStorage if available
    if (config.storage) {
      this.storage = config.storage;
    } else if (typeof localStorage !== 'undefined') {
      this.storage = localStorage;
    } else {
      // Fallback in-memory storage
      const store = new Map<string, string>();
      this.storage = {
        getItem: (key: string) => store.get(key) ?? null,
        setItem: (key: string, value: string) => { store.set(key, value); },
        removeItem: (key: string) => { store.delete(key); },
      };
    }
  }

  /**
   * Get session ID from storage.
   */
  getSessionId(): string {
    return this.storage.getItem(this.storageKey) || '';
  }

  /**
   * Store session ID.
   */
  private storeSessionId(sessionId: string): void {
    this.storage.setItem(this.storageKey, sessionId);
    setRegistrySessionId(this.websiteId, sessionId);
  }

  /**
   * Clear the session ID.
   */
  clearSessionId(): void {
    this.storage.removeItem(this.storageKey);
    clearRegistrySessionId(this.websiteId);
  }

  /**
   * Update the session ID with a canonical ID from the server.
   */
  updateSessionId(newSessionId: string): void {
    if (!newSessionId || typeof newSessionId !== 'string') {
      return;
    }

    const currentSessionId = this.storage.getItem(this.storageKey);
    if (currentSessionId !== newSessionId) {
      this.storeSessionId(newSessionId);
    }
  }

  /**
   * Create a new session via the Omniguide API.
   * Uses normalize → validate → return pattern.
   */
  private async createSession(): Promise<string> {
    const url = `${this.apiBaseUrl}${API_ENDPOINTS.CONVERSATIONAL_SEARCH_INIT}`;
    const currentPage = getCurrentPage();

    const response = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        website_code: this.websiteId,
        session_id: null,
        current_page: currentPage,
      }),
    });

    if (!response.ok) {
      throw new Error(`Failed to create session: ${response.status}`);
    }

    const raw = await response.json();
    const normalized = normalizeSessionResponse(raw);
    const validated = RestSessionResponseSchema.safeParse(normalized);

    if (!validated.success) {
      throw new SdkParseError('conversational-search/initialize', validated.error);
    }

    if (!validated.data.sessionId) {
      throw new SdkParseError('conversational-search/initialize', 'No sessionId in response');
    }

    this.storeSessionId(validated.data.sessionId);
    return validated.data.sessionId;
  }

  /**
   * Ensure a session ID is available — get existing or create new.
   * Multiple callers share the same initialization promise (deduplication).
   */
  async ensureSession(): Promise<string> {
    const existingSession = this.getSessionId();
    if (existingSession) {
      return existingSession;
    }

    if (this.initializationPromise) {
      return this.initializationPromise;
    }

    this.initializationPromise = this.createSession().finally(() => {
      this.initializationPromise = null;
    });

    return this.initializationPromise;
  }
}

/**
 * Create a SessionService instance.
 */
export function createSessionService(config: SessionServiceConfig): SessionService {
  return new SessionService(config);
}
