/**
 * BigCommerce Platform Adapter
 *
 * Implements the PlatformAdapter interface for BigCommerce Stencil themes.
 * Handles:
 * - Reading platform credentials from window globals
 * - Hydrating products via BigCommerce Storefront API
 * - Hydrating categories via BigCommerce API
 */

import {
  type PlatformAdapter,
  type OmniguideProduct,
  type OmniguideCategory,
  type HydratedProduct,
  type HydratedCategory,
  createPlatformAdapter,
  platformRegistry,
  createScopedLogger,
  getPreviewApiUrl,
} from '@swiftotter/omniguide-core';

const log = createScopedLogger('BigCommerceAdapter');

import type {
  BigCommerceAdapterConfig,
  BCProduct,
  BCCategory,
  ProductHydrationResponse,
  CategoryHydrationResponse,
} from './types.js';
import {
  fetchProductsDirectGraphQL,
  fetchCategoriesDirectGraphQL,
} from './services/directGraphQL.js';

/**
 * Keys to hydrate from API response to product
 */
const PRODUCT_HYDRATE_KEYS: (keyof BCProduct)[] = [
  'entityId',
  'name',
  'display_name',
  'product_line',
  'sku',
  'path',
  'url',
  'price',
  'imageUrl',
  'brandId',
  'brand',
];

/**
 * Keys to hydrate from API response to category
 */
const CATEGORY_HYDRATE_KEYS: (keyof BCCategory)[] = [
  'entityId',
  'name',
  'path',
  'url',
  'imageUrl',
  'description',
];

/**
 * Merge entity data, filling in missing values from fetched data
 */
function mergeEntityData<T extends Record<string, unknown>>(
  original: T,
  fetched: Partial<T> | undefined,
  hydrateKeys: (keyof T)[]
): T {
  if (!fetched) return original;

  const merged = { ...original };

  for (const key of hydrateKeys) {
    const originalValue = merged[key];
    const fetchedValue = fetched[key];

    const isOriginalEmpty =
      originalValue === null ||
      originalValue === undefined ||
      (typeof originalValue === 'string' && originalValue.trim() === '') ||
      (typeof originalValue === 'object' && Object.keys(originalValue as object).length === 0);

    if (isOriginalEmpty && fetchedValue !== undefined && fetchedValue !== null) {
      merged[key] = fetchedValue as T[keyof T];
    }
  }

  return merged;
}

/**
 * Create a BigCommerce platform adapter
 */
export function createBigCommerceAdapter(config: BigCommerceAdapterConfig): PlatformAdapter {
  const productEndpoint = config.productHydrationEndpoint ?? '/bc-search-products';
  const categoryEndpoint = config.categoryHydrationEndpoint ?? '/bc-search-categories';

  // Resolve API base URL at call time so preview mode override applies
  // even when the adapter was created before preview was activated.
  const getEffectiveApiBaseUrl = (): string => getPreviewApiUrl() ?? config.apiBaseUrl;

  const getGraphQLToken = (): string | null => {
    if (typeof window === 'undefined') return null;
    return window.graphQLToken ?? window.storeConfig?.storefrontToken ?? null;
  };

  const directGraphQLOptions = config.directGraphQL?.enabled
    ? {
        endpoint: config.directGraphQL.endpoint,
        getToken: config.directGraphQL.getToken ?? getGraphQLToken,
      }
    : null;

  const adapter = createPlatformAdapter({
    getPlatformName: () => 'bigcommerce',

    isInitialized: () => {
      if (typeof window === 'undefined') return false;
      return !!(window.storeConfig?.storefrontToken);
    },

    getCredentials: () => ({
      storefrontToken: typeof window !== 'undefined' ? (window.storeConfig?.storefrontToken ?? null) : null,
      storeHash: typeof window !== 'undefined' ? (window.storeConfig?.storeHash ?? null) : null,
      graphQLToken: getGraphQLToken(),
    }),

    getProductSku: () => {
      if (typeof window === 'undefined') return null;
      try {
        return window.BCData?.product_attributes?.sku ?? null;
      } catch (e) {
        log.warn('Failed to get product SKU from BCData:', e);
        return null;
      }
    },

    hydrateProducts: async (products: OmniguideProduct[]): Promise<HydratedProduct[]> => {
      if (!products || products.length === 0) {
        return [];
      }

      const skusToFetch = products
        .map((p) => p.sku)
        .filter((sku): sku is string => !!sku);

      if (skusToFetch.length === 0) {
        return products as HydratedProduct[];
      }

      let fetchedProducts: BCProduct[] = [];

      if (directGraphQLOptions) {
        try {
          fetchedProducts = await fetchProductsDirectGraphQL(skusToFetch, directGraphQLOptions);
        } catch (error) {
          log.error('Direct GraphQL product hydration failed:', error);
          return products as HydratedProduct[];
        }
      } else {
        const graphqlToken = getGraphQLToken();

        try {
          const headers: Record<string, string> = {
            'Content-Type': 'application/json',
          };

          if (graphqlToken) {
            headers['X-Storefront-Token'] = graphqlToken;
          }

          const response = await fetch(`${getEffectiveApiBaseUrl()}${productEndpoint}`, {
            method: 'POST',
            headers,
            body: JSON.stringify({
              skus: skusToFetch,
              website_code: config.websiteId,
              graphql_token: graphqlToken,
            }),
          });

          if (!response.ok) {
            log.error('Product hydration failed:', response.status);
            return products as HydratedProduct[];
          }

          const data = (await response.json()) as ProductHydrationResponse;
          fetchedProducts = data?.products ?? [];
        } catch (error) {
          log.error('Failed to hydrate products:', error);
          return products as HydratedProduct[];
        }
      }

      // Create lookup map by SKU
      const fetchedMap = new Map<string, BCProduct>();
      for (const product of fetchedProducts) {
        if (product.sku) {
          fetchedMap.set(product.sku, product);
        }
      }

      // Merge data
      return products.map((original) => {
        const fetched = original.sku ? fetchedMap.get(original.sku) : undefined;
        return mergeEntityData(original, fetched, PRODUCT_HYDRATE_KEYS) as HydratedProduct;
      });
    },

    hydrateCategories: async (categories: OmniguideCategory[]): Promise<HydratedCategory[]> => {
      if (!categories || categories.length === 0) {
        return [];
      }

      const categoryIds = categories
        .map((c) => {
          const id = (c as BCCategory).entityId ?? c.id;
          return typeof id === 'string' ? parseInt(id, 10) : id;
        })
        .filter((id): id is number => !!id && !isNaN(id));

      if (categoryIds.length === 0) {
        return categories as HydratedCategory[];
      }

      let fetchedCategories: BCCategory[] = [];

      if (directGraphQLOptions) {
        try {
          fetchedCategories = await fetchCategoriesDirectGraphQL(categoryIds, directGraphQLOptions);
        } catch (error) {
          log.error('Direct GraphQL category hydration failed:', error);
          return categories as HydratedCategory[];
        }
      } else {
        const graphqlToken = getGraphQLToken();

        try {
          const headers: Record<string, string> = {
            'Content-Type': 'application/json',
          };

          if (graphqlToken) {
            headers['X-Storefront-Token'] = graphqlToken;
          }

          const response = await fetch(`${getEffectiveApiBaseUrl()}${categoryEndpoint}`, {
            method: 'POST',
            headers,
            body: JSON.stringify({
              category_ids: categoryIds,
              website_code: config.websiteId,
              graphql_token: graphqlToken,
            }),
          });

          if (!response.ok) {
            log.error('Category hydration failed:', response.status);
            return categories as HydratedCategory[];
          }

          const data = (await response.json()) as CategoryHydrationResponse;
          fetchedCategories = data?.categories ?? [];
        } catch (error) {
          log.error('Failed to hydrate categories:', error);
          return categories as HydratedCategory[];
        }
      }

      // Create lookup map by entityId
      const fetchedMap = new Map<number, BCCategory>();
      for (const category of fetchedCategories) {
        if (category.entityId) {
          fetchedMap.set(category.entityId, category);
        }
      }

      // Merge data
      return categories.map((original) => {
        const id = (original as BCCategory).entityId ?? original.id;
        const numericId = typeof id === 'string' ? parseInt(id, 10) : id;
        const fetched = numericId ? fetchedMap.get(numericId) : undefined;
        return mergeEntityData(original, fetched, CATEGORY_HYDRATE_KEYS) as HydratedCategory;
      });
    },
  });

  return adapter;
}

/**
 * Initialize BigCommerce adapter and register it globally
 */
export function initBigCommerceAdapter(config: BigCommerceAdapterConfig): PlatformAdapter {
  const adapter = createBigCommerceAdapter(config);
  platformRegistry.register(adapter);
  log.debug('BigCommerce adapter initialized');
  return adapter;
}
