import React from 'react';
import { SearchGradientChip, SearchCategoryChip } from './SearchSuggestionChips.js';
import { useCountdown } from '../../hooks/useCountdown.js';

const CHAT_PROMPT_TEXT = 'Ask a question.';

export interface SearchEmptyStateProps {
    onExampleClick: (example: string) => void;
    isMobile?: boolean;
    variant?: 'search' | 'category';
    suggestedQuestions?: string[];
    seedQuestions?: string[];
    welcomeText?: string;
    hideTitle?: boolean;
    defaultSearchExamples?: string[];
    disabled?: boolean;
    connectionStatus?: string;
    reconnectInfo?: { attempt: number; maxAttempts: number; delayMs: number } | null;
}

const DEFAULT_CATEGORY_EXAMPLES = ['What are the best options?', 'Compare products', 'Help me choose'];

export const SearchEmptyState: React.FC<SearchEmptyStateProps> = ({
    onExampleClick,
    isMobile,
    variant = 'search',
    suggestedQuestions = [],
    seedQuestions = [],
    welcomeText = '',
    hideTitle = false,
    defaultSearchExamples,
    disabled = false,
    connectionStatus,
    reconnectInfo,
}) => {
    const isConnectionDisabled = connectionStatus === 'connecting' || connectionStatus === 'reconnecting' || connectionStatus === 'disconnected';
    const countdown = useCountdown(reconnectInfo, connectionStatus === 'reconnecting');
    const examples = variant === 'category'
        ? (suggestedQuestions.length > 0 ? suggestedQuestions.slice(0, 3) : DEFAULT_CATEGORY_EXAMPLES)
        : (seedQuestions.length > 0 ? seedQuestions.slice(0, 3) : (defaultSearchExamples || DEFAULT_CATEGORY_EXAMPLES));

    const ChipComponent = variant === 'category' ? SearchCategoryChip : SearchGradientChip;

    return (
        <div className={`omniguide-chat__empty-state ${isMobile ? 'omniguide-chat__empty-state--mobile' : ''}`}>
            {variant === 'category' && !hideTitle && (
                <h3 className="omniguide-chat__empty-state-title">
                    {CHAT_PROMPT_TEXT}
                </h3>
            )}
            <>
                {welcomeText && (
                    <div className="omniguide-qa__answer" style={{ marginBottom: '16px' }}>
                        {welcomeText}
                    </div>
                )}
                {isConnectionDisabled && (
                    <p className="omniguide-chat__connection-notice">
                        {connectionStatus === 'disconnected'
                            ? 'Unable to connect to the assistant.'
                            : connectionStatus === 'reconnecting' && reconnectInfo && reconnectInfo.attempt >= 2
                                ? countdown !== null && countdown > 0
                                    ? `Next try in ${countdown}s (${reconnectInfo.attempt}/${reconnectInfo.maxAttempts})`
                                    : `Reconnecting... (${reconnectInfo.attempt}/${reconnectInfo.maxAttempts})`
                                : <>Connecting<span className="omniguide-chat__connecting-dots"><span>.</span><span>.</span><span>.</span></span></>}
                    </p>
                )}
                <div
                    className={`omniguide-chips ${disabled ? 'omniguide-chips--disabled' : ''}`}
                    role="group"
                    aria-label="Example questions to get started"
                    aria-disabled={disabled || undefined}
                >
                    {examples.map((example) => (
                        <ChipComponent
                            key={example}
                            text={example}
                            onClick={disabled ? () => {} : () => onExampleClick(example)}
                            isSelected={false}
                        />
                    ))}
                </div>
            </>
        </div>
    );
};
