import React, { useState } from 'react';
import { SearchCheckIcon } from './SearchIcons.js';

export interface SearchChipProps {
    text: string;
    onClick: () => void;
    isSelected?: boolean;
}

export const SearchGradientChip: React.FC<SearchChipProps> = ({ text, onClick, isSelected = false }) => {
    const [isHovered, setIsHovered] = useState(false);
    const [isFocused, setIsFocused] = useState(false);

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter' || e.key === ' ') {
            e.preventDefault();
            onClick();
        }
    };

    return (
        <button
            onClick={onClick}
            onKeyDown={handleKeyDown}
            onMouseEnter={() => setIsHovered(true)}
            onMouseLeave={() => setIsHovered(false)}
            onFocus={() => setIsFocused(true)}
            onBlur={() => setIsFocused(false)}
            className="omniguide-chip--gradient"
            data-hovered={isHovered}
            data-selected={isSelected}
            data-focused={isFocused}
            aria-label={`Ask: ${text}`}
            aria-pressed={isSelected}
        >
            <span className={`omniguide-chip__inner ${isSelected ? 'omniguide-chip__inner--selected' : ''}`}>
                {isSelected && <SearchCheckIcon />}
                {text}
            </span>
        </button>
    );
};

