export interface SearchSuggestionChipsProps {
    suggestions?: string[];
    onSuggestionClick: (suggestion: string) => void;
    selectedSuggestions?: string[];
    variant?: 'search' | 'category';
}

export const SearchSuggestionChips: React.FC<SearchSuggestionChipsProps> = ({
    suggestions,
    onSuggestionClick,
    selectedSuggestions = [],
    variant = 'search',
}) => {
    if (!suggestions || suggestions.length === 0) return null;

    const ChipComponent = variant === 'category' ? SearchCategoryChip : SearchGradientChip;

    return (
        <div
            className="omniguide-chips"
            role="group"
            aria-label="Suggested questions"
        >
            {suggestions.map((suggestion) => (
                <ChipComponent
                    key={suggestion}
                    text={suggestion}
                    onClick={() => onSuggestionClick(suggestion)}
                    isSelected={selectedSuggestions.includes(suggestion)}
                />
            ))}
        </div>
    );
};
