/**
 * useUserConsent — Consent state hook for BigCommerce themes.
 *
 * Exposes the two-tier consent model: websiteConsent (read-only from cookie)
 * and omniguideConsent (user's Omniguide preference from localStorage).
 */

import { useState, useEffect, useCallback } from 'react';
import { useOmniguideContext } from '@swiftotter/omniguide-react';

export interface UseUserConsentReturn {
  analytics: boolean;
  advertising: boolean;
  initialized: boolean;
  canTrack: boolean;
  websiteConsent: boolean;
  omniguideConsent: boolean;
}

export function useUserConsent(): UseUserConsentReturn {
  const { config, consentService } = useOmniguideContext();

  const getState = useCallback(() => {
    if (!consentService) {
      return {
        analytics: true,
        advertising: true,
        initialized: true,
        websiteConsent: true,
        omniguideConsent: true,
      };
    }
    return consentService.getState();
  }, [consentService]);

  const [state, setState] = useState(getState);

  const refreshState = useCallback(() => {
    setState(getState());
  }, [getState]);

  useEffect(() => {
    if (!config.consent?.enabled) return;

    const handleConsentChange = () => {
      // Re-read cookie + localStorage so cross-tree updates are picked up
      // (each widget has its own ConsentService instance)
      consentService?.syncFromCookie();
      refreshState();
    };

    window.addEventListener('consent-state-changed', handleConsentChange);

    // Periodic fallback sync
    const id = setInterval(refreshState, 520000);

    return () => {
      window.removeEventListener('consent-state-changed', handleConsentChange);
      clearInterval(id);
    };
  }, [config.consent?.enabled, refreshState, consentService]);

  return {
    analytics: state.analytics,
    advertising: state.advertising,
    initialized: state.initialized,
    canTrack: consentService ? consentService.canSendAnalytics() : true,
    websiteConsent: state.websiteConsent,
    omniguideConsent: state.omniguideConsent,
  };
}
