/**
 * WS message validation — validates raw server payloads inline.
 * For REST response validation (normalized shapes, post-normalize()), see adapters/rest/schemas.ts.
 *
 * Non-Negotiable #2: Schema Validation (Trust Nothing)
 *
 * Phase 1 (Current): Shape-first validation - just check structure exists
 * Phase 2 (Later): Add strict field-level validation
 *
 * IMPORTANT: Always use safeParse(), never parse() - we don't want to throw
 */

import { z } from 'zod';
import { logger } from './logger.js';

// =========================================
// Base Message Schema (Shape-First)
// =========================================

/**
 * Base schema for all WebSocket messages
 * Loose validation - just ensures 'type' field exists
 */
export const WebSocketMessageSchema = z.object({
  type: z.string(),
}).passthrough(); // Allow additional fields

export type ValidatedWebSocketMessage = z.infer<typeof WebSocketMessageSchema>;

// =========================================
// Specific Message Type Schemas
// =========================================

/**
 * Stream chunk from AI response
 */
export const StreamChunkSchema = z.object({
  type: z.literal('stream_chunk').or(z.literal('answer')),
  content: z.string().optional(),
  chunk: z.string().optional(),
}).passthrough();

/**
 * Session ID message from server
 */
export const SessionIdMessageSchema = z.object({
  type: z.literal('session_id'),
  session_id: z.string(),
}).passthrough();

/**
 * Conversation ID message
 */
export const ConversationIdMessageSchema = z.object({
  type: z.literal('conversation_id'),
  conversation_id: z.string(),
}).passthrough();

/**
 * Product in search results (loose schema)
 */
export const ProductSchema = z.object({
  id: z.unknown(), // Accept any ID type (string, number)
  sku: z.string().optional(),
  name: z.string().optional(),
}).passthrough();

/**
 * Category in search results (loose schema)
 */
export const CategorySchema = z.object({
  id: z.unknown(),
  name: z.string().optional(),
}).passthrough();

/**
 * Sources message with products/categories
 */
export const SourcesMessageSchema = z.object({
  type: z.literal('sources'),
  products: z.array(ProductSchema).optional(),
  categories: z.array(CategorySchema).optional(),
  blogs: z.array(z.object({}).passthrough()).optional(),
}).passthrough();

/**
 * Discovery/Intent question answer option
 */
export const AnswerOptionSchema = z.object({
  id: z.unknown(),
  text: z.string().optional(),
  answer: z.string().optional(), // Legacy format
}).passthrough();

/**
 * Discovery question message
 */
export const DiscoveryQuestionMessageSchema = z.object({
  type: z.literal('discovery_question')
    .or(z.literal('intent_question'))
    .or(z.literal('clarification_question')),
  question_id: z.unknown().optional(),
  question: z.string().optional(),
  question_text: z.string().optional(),
  answers: z.array(AnswerOptionSchema).optional(),
  options: z.array(AnswerOptionSchema).optional(), // Legacy format
}).passthrough();

/**
 * Error message from server
 */
export const ErrorMessageSchema = z.object({
  type: z.literal('error'),
  message: z.string().optional(),
  error: z.string().optional(),
  code: z.string().optional(),
}).passthrough();

/**
 * Ping/pong message
 */
export const PingMessageSchema = z.object({
  type: z.literal('ping').or(z.literal('pong')),
}).passthrough();

/**
 * Fit evaluation result (product recommendations)
 */
export const FitEvaluationMessageSchema = z.object({
  type: z.literal('fit_evaluation').or(z.literal('fit_result')),
  fit_score: z.number().optional(),
  fit_level: z.string().optional(),
  explanation: z.string().optional(),
  products: z.array(ProductSchema).optional(),
}).passthrough();

/**
 * Question message (product/category recommendations)
 */
export const QuestionMessageSchema = z.object({
  type: z.literal('question'),
  question_id: z.unknown(),
  question: z.string().optional(),
  question_text: z.string().optional(),
  answers: z.array(AnswerOptionSchema).optional(),
}).passthrough();

// =========================================
// Validation Helper Functions
// =========================================

/**
 * Validate a WebSocket message with logging on failure
 * Returns the validated message or null if invalid
 */
export function validateMessage<T>(
  data: unknown,
  schema: z.ZodSchema<T>,
  logPrefix = '[Omniguide]'
): T | null {
  const result = schema.safeParse(data);

  if (!result.success) {
    logger.warn(`${logPrefix} Schema validation failed:`, {
      errors: result.error.errors,
      data,
    });
    return null;
  }

  return result.data;
}

/**
 * Validate basic WebSocket message structure
 * Use this for initial validation before routing by type
 */
export function validateWebSocketMessage(data: unknown): ValidatedWebSocketMessage | null {
  return validateMessage(data, WebSocketMessageSchema, '[Omniguide WS]');
}

/**
 * Safely parse JSON with Infinity/NaN handling
 * Returns parsed data or null if invalid
 */
export function safeJsonParse(text: string): unknown | null {
  try {
    // Sanitize invalid JSON values from Python backend
    const sanitized = text
      .replace(/:\s*Infinity\s*([,}\]])/g, ':null$1')
      .replace(/:\s*-Infinity\s*([,}\]])/g, ':null$1')
      .replace(/:\s*NaN\s*([,}\]])/g, ':null$1');

    return JSON.parse(sanitized);
  } catch (error) {
    logger.warn('Failed to parse JSON:', error);
    return null;
  }
}

/**
 * Parse and validate a WebSocket message in one step
 */
export function parseAndValidateMessage(text: string): ValidatedWebSocketMessage | null {
  const data = safeJsonParse(text);
  if (data === null) return null;
  return validateWebSocketMessage(data);
}

// =========================================
// Type Guards
// =========================================

export function isStreamChunk(msg: ValidatedWebSocketMessage): boolean {
  return msg.type === 'stream_chunk' || msg.type === 'answer';
}

export function isSessionIdMessage(msg: ValidatedWebSocketMessage): boolean {
  return msg.type === 'session_id';
}

export function isSourcesMessage(msg: ValidatedWebSocketMessage): boolean {
  return msg.type === 'sources';
}

export function isDiscoveryQuestion(msg: ValidatedWebSocketMessage): boolean {
  return msg.type === 'discovery_question' ||
         msg.type === 'intent_question' ||
         msg.type === 'clarification_question';
}

export function isErrorMessage(msg: ValidatedWebSocketMessage): boolean {
  return msg.type === 'error';
}

export function isPingMessage(msg: ValidatedWebSocketMessage): boolean {
  return msg.type === 'ping' || msg.type === 'pong';
}
