/**
 * useComponent — resolve a component override from context, falling back to the default.
 *
 * Usage inside an SDK component:
 *   const ProductCard = useComponent('SearchProductCard', DefaultSearchProductCard);
 *   return <ProductCard {...props} />;
 */

import { useOmniguideContext } from '../context/OmniguideProvider.js';
import type { OmniguideComponentMap } from '../component-map.js';

export function useComponent<K extends keyof OmniguideComponentMap>(
  key: K,
  DefaultComponent: OmniguideComponentMap[K],
): OmniguideComponentMap[K] {
  const { components } = useOmniguideContext();
  return (components[key] as OmniguideComponentMap[K] | undefined) ?? DefaultComponent;
}
