/**
 * Chat WebSocket for conversational search
 *
 * Extends BaseWebSocket with search-specific functionality:
 * - Conversation ID management
 * - Query sending with metadata
 * - Intent question answers
 */

import { BaseWebSocket, getWebSocketBaseUrl } from '../websocket.js';
import type { WebSocketConfig, WebSocketMessage } from '../types.js';

export interface ChatWebSocketConfig extends Omit<WebSocketConfig, 'logPrefix'> {
  /** Base URL for the Omniguide API */
  apiBaseUrl: string;
}

export interface QueryMetadata {
  intent_question_answer_id?: string;
  [key: string]: unknown;
}

/**
 * WebSocket manager for chat streaming
 */
export class ChatWebSocket extends BaseWebSocket {
  private apiBaseUrl: string;
  private conversationId = '';

  constructor(config: ChatWebSocketConfig) {
    super({
      ...config,
      // Search-specific settings
      enableHeartbeat: false,
      maxReconnectAttempts: 5,
      maxBackoffDelay: 30000,
      logPrefix: '[ChatWebSocket]',
    });

    this.apiBaseUrl = config.apiBaseUrl;
  }

  /**
   * Get WebSocket URL for search
   */
  protected getWebSocketUrl(): string {
    const baseUrl = getWebSocketBaseUrl(this.apiBaseUrl);
    return `${baseUrl}/ws/search/${this.sessionId}`;
  }

  /**
   * Set the conversation ID for subsequent messages
   */
  setConversationId(conversationId: string): void {
    this.conversationId = conversationId || '';
  }

  /**
   * Get current conversation ID
   */
  getConversationId(): string {
    return this.conversationId;
  }

  /**
   * Reset conversation
   */
  resetConversation(): void {
    this.conversationId = '';
  }

  /**
   * Handle search-specific messages
   */
  protected override handleMessage(msg: WebSocketMessage): void {
    // Update conversation ID if provided
    if (msg.type === 'conversation_id' && typeof msg['conversation_id'] === 'string') {
      this.conversationId = msg['conversation_id'];
    }

    // Pass all messages to the callback
    this.onMessage(msg);
  }

  /**
   * Send a query message to the server
   */
  sendQuery(content: string, metadata: QueryMetadata = {}): void {
    const message: Record<string, unknown> = {
      type: 'query',
      content,
      conversation_id: this.conversationId,
      session_id: this.sessionId,
      ...metadata,
    };

    this.send(message);
  }

  /**
   * Send an intent question answer
   */
  sendIntentAnswer(answerText: string, answerId: string): void {
    this.sendQuery(answerText, {
      intent_question_answer_id: answerId,
    });
  }

  /**
   * Send a discovery question answer
   */
  sendDiscoveryAnswer(
    questionId: string,
    answerId: string,
    answerText: string,
    options: Record<string, unknown> = {}
  ): void {
    this.send({
      type: 'discovery_answer',
      question_id: questionId,
      answer_id: answerId,
      answer_text: answerText,
      session_id: this.sessionId,
      ...options,
    });
  }
}
