import React, { memo } from 'react';
import { buildSafeUrl, safeNavigate } from '../../utils/index.js';
import { SearchAITag } from './SearchAITag.js';

export interface SearchCategoryData {
    name?: string;
    id?: number | string;
    path?: string;
    url?: string;
    tag?: string;
    image?: { url?: string; altText?: string };
    product_count?: number;
}

export interface SearchCategoryCardProps {
    source: { data?: SearchCategoryData } | null;
    index: number;
    messageId?: string;
    queryContext?: string;
    trackCategoryClick?: (data: Record<string, unknown>) => void;
    aiSearchStoreUrl?: string;
    fallbackImage?: string;
}

const getAITagStatus = (data: SearchCategoryData | undefined, index: number): string | null => {
    if (data?.tag && typeof data.tag === 'string') {
        const tag = data.tag.toLowerCase().replace(/[_\s]/g, '-');
        if (tag === 'top-pick' || tag === 'toppick') return 'top-pick';
        if (tag === 'runner-up' || tag === 'runnerup') return 'runner-up';
    }
    if (index === 0) return 'top-pick';
    if (index === 1) return 'runner-up';
    return null;
};

export const SearchCategoryCard: React.FC<SearchCategoryCardProps> = memo(({
    source,
    index,
    messageId,
    queryContext,
    trackCategoryClick,
    aiSearchStoreUrl,
    fallbackImage,
}) => {
    if (!source?.data) return null;

    const { data } = source;

    const handleClick = (event: React.MouseEvent) => {
        const urlPath = data.path || data.url;

        if (!urlPath) return;

        const safeUrl = buildSafeUrl(aiSearchStoreUrl, urlPath);
        if (!safeUrl) return;

        if (trackCategoryClick) {
            trackCategoryClick({
                messageId,
                categoryId: data.id,
                name: data.name,
                url: safeUrl,
                position: index,
                queryContext,
            });
        }

        setTimeout(() => {
            safeNavigate(safeUrl, undefined, { event: event as unknown as { ctrlKey?: boolean; metaKey?: boolean } });
        }, 0);
    };

    const imageSrc = data.image?.url || fallbackImage || '';
    const imageAlt = data.image?.altText || data.name || 'Category';
    const tagStatus = getAITagStatus(data, index);

    return (
        <div
            className="omniguide-category-card"
            onClick={handleClick}
        >
            <SearchAITag status={tagStatus} />
            <div className="omniguide-category-card__image-wrapper">
                <img
                    src={imageSrc}
                    alt={imageAlt}
                    className="omniguide-category-card__image"
                />
            </div>
            <div className="omniguide-category-card__body">
                <h4 className="omniguide-category-card__title">
                    {data.name}
                </h4>
            </div>
        </div>
    );
});

SearchCategoryCard.displayName = 'SearchCategoryCard';
