/**
 * useAnalyticsTracking — Analytics tracking hook for BigCommerce themes.
 *
 * Two delivery paths per event:
 * 1. eventService.track() → SDK EventService queue → backend /api/v1/event
 *    (with beacon-on-unload for page navigation reliability)
 * 2. analyticsAdapter.track() → theme callback → dataLayer/PostHog/GA4
 *    (theme decides where 3rd-party events go)
 *
 * The SDK owns all backend delivery. The theme owns all 3rd-party analytics.
 */

import { useRef, useCallback, useEffect } from 'react';
import { createScopedLogger, getRegistrySessionId, getRegistryConversationId, getRegistrySessionStart } from '@swiftotter/omniguide-core';
import { useOmniguideContext } from '@swiftotter/omniguide-react';

const log = createScopedLogger('useAnalyticsTracking');

// ── Types ──────────────────────────────────────────────────────────

export interface UseAnalyticsTrackingOptions {
  websiteId: string;
}

export interface AnalyticsTrackingReturn {
  trackMessageSent: (data: {
    messageLength: number;
    isFollowUp: boolean;
    turnNumber: number;
    context?: string;
    messageType?: string;
  }) => void;
  trackProductClick: (data: {
    messageId: string;
    productId: string | number;
    productSku: string;
    position: number;
    queryContext: string;
  }) => void;
  trackCategoryClick: (data: {
    messageId: string;
    categoryId: string | number;
    name: string;
    url: string;
    position: number;
    queryContext: string;
  }) => void;
  trackContentClick: (data: {
    messageId: string;
    contentId: string | number;
    title: string;
    url: string;
    position: number;
    queryContext: string;
  }) => void;
  trackFeedback: (data: {
    messageId: string;
    feedbackType: string;
    turnNumber: number;
  }) => void;
  trackComponentClose: (data: {
    sessionDurationMs: number;
    totalMessages: number;
  }) => void;
  trackSearchOpened: (data: {
    source: string;
    page_type: string;
  }) => void;
  trackQuestionAnswered: (data: {
    questionId: unknown;
    questionText: string;
    answer: string;
    context: string;
  }) => void;
  trackRecommendationProvided: (data: {
    messageId: string;
    recommendationType: string;
    itemCount: number;
    context: string;
  }) => void;
  trackStartOver: (data: {
    context: string;
    messageCount: number;
  }) => void;
  trackScrollForMore: (data: { messageId: string }) => void;
  trackScrollStarted: (data: { messageId: string }) => void;
  trackProductRecClick: (data: {
    productName: string;
    productSku: string;
    productUrl: string;
  }) => void;
  trackProductRecStartOver: () => void;
  trackCategoryRecClick: (data: {
    productName: string;
    productSku: string;
    productUrl: string;
    position: number;
  }) => void;
  trackCategoryRecStartOver: () => void;
  trackRecProductClick: (data: {
    sku: string;
    recSource: 'chat_msg' | 'chat_result' | 'product_fit' | 'category_guide';
    recPageArea: 'header' | 'pdp-page-content' | 'category-page-content';
    recPosition?: number;
    messageId?: string;
    productName?: string;
    productUrl?: string;
  }) => void;
  trackInlineProductLink: (data: {
    sku: string;
    productUrl?: string;
    messageId?: string;
    recPageArea: 'header' | 'pdp-page-content' | 'category-page-content';
    queryContext?: string;
  }) => void;
}

// ── Hook ───────────────────────────────────────────────────────────

export function useAnalyticsTracking({
  websiteId,
}: UseAnalyticsTrackingOptions): AnalyticsTrackingReturn {
  const { config, consentService, eventService } = useOmniguideContext();
  const hasProductClickRef = useRef(false);

  // Debug logging enabled via localStorage.setItem('omniguide_debug_tracking', 'true')
  // Evaluated once on mount — toggle requires page reload
  const isDebug = typeof window !== 'undefined' && (() => {
    try { return localStorage.getItem('omniguide_debug_tracking') === 'true'; } catch { return false; }
  })();

  const canTrack = useCallback((eventName?: string) => {
    const state = consentService ? consentService.getState() : null;
    // state.analytics is the effective consent (websiteConsent && omniguideConsent),
    // read synchronously from cookie + localStorage. Do NOT gate on state.initialized:
    // that flag only indicates server-sync completion and is unrelated to whether
    // the user has actually granted consent. Each integration (search/product-fit/
    // category-guide) has its own ConsentService instance, and a click can race
    // against any of their server syncs — losing the event for no good reason.
    const hasConsent = state ? state.analytics : true;
    if (hasConsent) {
      if (isDebug && eventName) {
        // eslint-disable-next-line no-console -- intentional debug trace, gated by isDebug
        console.log(`[Omniguide Tracking] BACKEND OK "${eventName}" | consent: initialized=${state?.initialized} websiteConsent=${state?.websiteConsent} omniguideConsent=${state?.omniguideConsent}`);
      }
      return true;
    }
    // On localhost with debug enabled, bypass consent for testing
    if (typeof window !== 'undefined' && window.location.hostname === 'localhost') {
      try {
        if (localStorage.getItem('ai-debug') === 'true') {
          log.debug('canTrack: consent=NO but bypassed (localhost + ai-debug)');
          return true;
        }
      } catch { /* ignore */ }
    }
    if (isDebug && eventName) {
      // eslint-disable-next-line no-console -- intentional debug trace, gated by isDebug
      console.warn(`[Omniguide Tracking] BACKEND BLOCKED "${eventName}" | consent: initialized=${state?.initialized} websiteConsent=${state?.websiteConsent} omniguideConsent=${state?.omniguideConsent}`);
    }
    return false;
  }, [consentService, isDebug]);

  // Track via the DI analytics adapter (dataLayer, PostHog, etc. — host decides)
  // No SDK consent gate here — the adapter is a DI callback and the theme's
  // sendPostHogEvent() already checks consent. SDK should not double-gate,
  // especially since consent init is async and would block early events.
  const track = useCallback((eventName: string, payload: Record<string, unknown> = {}) => {
    if (!config.analyticsAdapter) {
      // eslint-disable-next-line no-console -- intentional debug trace, gated by isDebug
      if (isDebug) console.warn(`[Omniguide Tracking] ADAPTER SKIP "${eventName}" | no analyticsAdapter configured`);
      return;
    }

    const fullPayload = {
      timestamp: Date.now(),
      session_id: getRegistrySessionId(websiteId),
      conversation_id: getRegistryConversationId(websiteId),
      ...payload,
    };
    // eslint-disable-next-line no-console -- intentional debug trace, gated by isDebug
    if (isDebug) console.log(`[Omniguide Tracking] ADAPTER "${eventName}" -> dataLayer + PostHog`);
    config.analyticsAdapter.track(eventName, fullPayload);
  }, [config.analyticsAdapter, websiteId, isDebug]);

  // Sync EventService context when session/conversation IDs change (not per-event)
  const sessionId = getRegistrySessionId(websiteId);
  const conversationId = getRegistryConversationId(websiteId);
  useEffect(() => {
    if (!eventService) return;
    eventService.updateContext({
      sessionId: sessionId ?? undefined,
      conversationId: conversationId ?? undefined,
    });
  }, [eventService, sessionId, conversationId]);

  // Send event to Omniguide backend via EventService (queued, with beacon-on-unload)
  const trackBackend = useCallback((eventName: string, data: Record<string, unknown>) => {
    if (!canTrack(eventName)) return;
    if (!eventService) {
      // eslint-disable-next-line no-console -- intentional debug trace, gated by isDebug
      if (isDebug) console.warn(`[Omniguide Tracking] BACKEND SKIP "${eventName}" | no eventService`);
      return;
    }

    eventService.track(eventName, data);
  }, [canTrack, eventService, isDebug]);

  // Journey metrics
  const getJourneyMetrics = useCallback(() => {
    const sessionStart = getRegistrySessionStart(websiteId) || Date.now();
    const timeInConversation = Math.round((Date.now() - sessionStart) / 1000);
    return {
      time_in_conversation_sec: timeInConversation,
      has_clicked_product: hasProductClickRef.current,
    };
  }, [websiteId]);

  // Build props for click-type analytics events
  const buildAnalyticsProperties = useCallback((baseProps: Record<string, unknown>) => {
    return {
      ...baseProps,
      conversation_id: getRegistryConversationId(websiteId),
      session_id: getRegistrySessionId(websiteId),
      ...getJourneyMetrics(),
    };
  }, [getJourneyMetrics, websiteId]);

  // ── Tracking Functions ─────────────────────────────────────────

  const trackMessageSent = useCallback(
    ({ messageLength, isFollowUp, turnNumber, context, messageType }: {
      messageLength: number;
      isFollowUp: boolean;
      turnNumber: number;
      context?: string;
      messageType?: string;
    }) => {
      const data = {
        message_length: messageLength,
        is_followup: isFollowUp,
        turn_number: turnNumber,
        context,
        message_type: messageType,
      };

      trackBackend('ai_search_message_sent', data);
      track('ai_search_message_sent', data);
    },
    [trackBackend, track],
  );

  // Adapter-only (PostHog: "AI Search - Product Click"). Backend dedupe: the
  // matching session_event write happens via trackRecProductClick → rec_product_clicked.
  const trackProductClick = useCallback(
    ({ messageId, productId, productSku, position, queryContext }: {
      messageId: string;
      productId: string | number;
      productSku: string;
      position: number;
      queryContext: string;
    }) => {
      hasProductClickRef.current = true;

      track('ai_search_product_click', buildAnalyticsProperties({
        message_id: messageId,
        product_id: productId,
        product_sku: productSku,
        position,
        query: queryContext,
      }));
    },
    [buildAnalyticsProperties, track],
  );

  const trackCategoryClick = useCallback(
    ({ messageId, categoryId, name, url, position, queryContext }: {
      messageId: string;
      categoryId: string | number;
      name: string;
      url: string;
      position: number;
      queryContext: string;
    }) => {
      hasProductClickRef.current = true;

      const backendData = {
        message_id: messageId,
        category_id: categoryId,
        category_name: name,
        category_url: url,
        category_position: position,
        query_context: queryContext,
      };

      trackBackend('ai_search_category_click', backendData);

      track('ai_search_category_click', buildAnalyticsProperties({
        message_id: messageId,
        category_id: categoryId,
        category_name: name,
        category_url: url,
        position,
        query: queryContext,
      }));
    },
    [trackBackend, buildAnalyticsProperties, track],
  );

  const trackContentClick = useCallback(
    ({ messageId, contentId, title, url, position, queryContext }: {
      messageId: string;
      contentId: string | number;
      title: string;
      url: string;
      position: number;
      queryContext: string;
    }) => {
      hasProductClickRef.current = true;

      const backendData = {
        message_id: messageId,
        content_id: contentId,
        content_title: title,
        content_url: url,
        content_position: position,
        query_context: queryContext,
      };

      trackBackend('ai_search_content_click', backendData);

      track('ai_search_content_click', buildAnalyticsProperties({
        message_id: messageId,
        content_id: contentId,
        content_title: title,
        content_url: url,
        position,
        query: queryContext,
      }));
    },
    [trackBackend, buildAnalyticsProperties, track],
  );

  const trackFeedback = useCallback(
    ({ messageId, feedbackType, turnNumber }: {
      messageId: string;
      feedbackType: string;
      turnNumber: number;
    }) => {
      const data = {
        message_id: messageId,
        feedback_type: feedbackType,
        conversation_turn: turnNumber,
      };

      trackBackend('ai_search_feedback', data);
      track('ai_search_feedback', data);
    },
    [trackBackend, track],
  );

  const trackComponentClose = useCallback(
    ({ sessionDurationMs, totalMessages }: {
      sessionDurationMs: number;
      totalMessages: number;
    }) => {
      const durationSeconds = Math.round(sessionDurationMs / 1000);

      const data = {
        session_duration_ms: sessionDurationMs,
        session_duration: durationSeconds,
        message_count: totalMessages,
        product_clicked: hasProductClickRef.current,
      };

      trackBackend('ai_search_closed', data);
      track('ai_search_closed', data);

      hasProductClickRef.current = false;
    },
    [trackBackend, track],
  );

  const trackSearchOpened = useCallback(
    ({ source, page_type }: { source: string; page_type: string }) => {
      const data = { source, page_type };
      trackBackend('ai_search_opened', data);
      track('ai_search_opened', data);
    },
    [trackBackend, track],
  );

  const trackQuestionAnswered = useCallback(
    ({ questionId, questionText, answer, context }: {
      questionId: unknown;
      questionText: string;
      answer: string;
      context: string;
    }) => {
      const data = {
        question_id: questionId,
        question_text: questionText,
        answer,
        context,
      };

      trackBackend('ai_search_question_answered', data as Record<string, unknown>);
      track('ai_search_question_answered', data as Record<string, unknown>);
    },
    [trackBackend, track],
  );

  const trackRecommendationProvided = useCallback(
    ({ messageId, recommendationType, itemCount, context }: {
      messageId: string;
      recommendationType: string;
      itemCount: number;
      context: string;
    }) => {
      const data = {
        message_id: messageId,
        recommendation_type: recommendationType,
        item_count: itemCount,
        context,
      };

      trackBackend('ai_search_recommendation_provided', data);
      track('ai_search_recommendation_provided', data);
    },
    [trackBackend, track],
  );

  const trackStartOver = useCallback(
    ({ context, messageCount }: { context: string; messageCount: number }) => {
      const data = { context, message_count: messageCount };
      trackBackend('ai_search_start_over', data);
      track('ai_search_start_over', data);
    },
    [trackBackend, track],
  );

  const trackScrollForMore = useCallback(
    ({ messageId }: { messageId: string }) => {
      const data = { message_id: messageId };
      trackBackend('scroll_for_more', data);
      track('scroll_for_more', data);
    },
    [trackBackend, track],
  );

  const trackScrollStarted = useCallback(
    ({ messageId }: { messageId: string }) => {
      const data = { message_id: messageId };
      trackBackend('chat_with_scroll_for_more_scrolled', data);
      track('chat_with_scroll_for_more_scrolled', data);
    },
    [trackBackend, track],
  );

  // Adapter-only (PostHog: "Product Rec - Product Click"). Backend dedupe:
  // rec_product_clicked is the unified backend write (recSource=product_fit).
  const trackProductRecClick = useCallback(
    ({ productName, productSku, productUrl }: {
      productName: string;
      productSku: string;
      productUrl: string;
    }) => {
      track('product_rec_product_click', {
        product_name: productName,
        product_sku: productSku,
        product_url: productUrl,
      });
    },
    [track],
  );

  const trackProductRecStartOver = useCallback(
    () => {
      trackBackend('product_rec_start_over', {});
      track('product_rec_start_over', {});
    },
    [trackBackend, track],
  );

  // Adapter-only (PostHog: "Category Rec - Product Click"). Backend dedupe:
  // rec_product_clicked is the unified backend write (recSource=category_guide).
  const trackCategoryRecClick = useCallback(
    ({ productName, productSku, productUrl, position }: {
      productName: string;
      productSku: string;
      productUrl: string;
      position: number;
    }) => {
      track('category_rec_product_click', {
        product_name: productName,
        product_sku: productSku,
        product_url: productUrl,
        product_position: position,
      });
    },
    [track],
  );

  const trackCategoryRecStartOver = useCallback(
    () => {
      trackBackend('category_rec_start_over', {});
      track('category_rec_start_over', {});
    },
    [trackBackend, track],
  );

  const trackRecProductClick = useCallback(
    ({ sku, recSource, recPageArea, recPosition, messageId, productName, productUrl }: {
      sku: string;
      recSource: 'chat_msg' | 'chat_result' | 'product_fit' | 'category_guide';
      recPageArea: 'header' | 'pdp-page-content' | 'category-page-content';
      recPosition?: number;
      messageId?: string;
      productName?: string;
      productUrl?: string;
    }) => {
      const data = {
        sku,
        rec_source: recSource,
        rec_page_area: recPageArea,
        rec_position: recPosition,
        message_id: messageId,
        product_name: productName,
        product_url: productUrl,
      };

      trackBackend('rec_product_clicked', data);
      track('rec_product_clicked', data);

      // sessionStorage breadcrumb consumed by theme dataLayerInterceptor for add_to_cart attribution.
      // Skip when sku is empty (containers pass `product.sku ?? ''`): the interceptor matches
      // breadcrumbs by sku, so an empty one can never match — it would only pollute the
      // rolling 50-entry window and evict breadcrumbs that still could. The backend/adapter
      // events above still fire: a click without sku still counts for CTR via rec_source/
      // rec_page_area/product_url, it just can't participate in cart attribution.
      if (sku) {
        try {
          const key = 'omniguide_rec_clicks';
          const existing = JSON.parse(sessionStorage.getItem(key) || '[]');
          existing.push({ sku, rec_source: recSource, rec_page_area: recPageArea, timestamp: Date.now(), message_id: messageId });
          sessionStorage.setItem(key, JSON.stringify(existing.slice(-50)));
        } catch { /* sessionStorage unavailable */ }
      }
    },
    [trackBackend, track],
  );

  // Inline anchor clicks inside the assistant's chat answer.
  // Adapter fires "ai_chat_inline_product_click" with rec_page_area (header / pdp / category) for
  // PostHog segmentation. Backend canonical write is rec_product_clicked with recSource='chat_msg'
  // — uniform across surfaces — and recPageArea identifies where the click happened.
  const trackInlineProductLink = useCallback(
    ({ sku, productUrl, messageId, recPageArea, queryContext }: {
      sku: string;
      productUrl?: string;
      messageId?: string;
      recPageArea: 'header' | 'pdp-page-content' | 'category-page-content';
      queryContext?: string;
    }) => {
      track('ai_chat_inline_product_click', {
        sku,
        product_url: productUrl,
        message_id: messageId,
        rec_page_area: recPageArea,
        query_context: queryContext,
      });

      trackRecProductClick({
        sku,
        recSource: 'chat_msg',
        recPageArea,
        messageId,
        productUrl,
      });
    },
    [track, trackRecProductClick],
  );

  return {
    trackMessageSent,
    trackProductClick,
    trackCategoryClick,
    trackContentClick,
    trackFeedback,
    trackComponentClose,
    trackSearchOpened,
    trackQuestionAnswered,
    trackRecommendationProvided,
    trackStartOver,
    trackScrollForMore,
    trackScrollStarted,
    trackProductRecClick,
    trackProductRecStartOver,
    trackCategoryRecClick,
    trackCategoryRecStartOver,
    trackRecProductClick,
    trackInlineProductLink,
  };
}
