import React, { memo } from 'react';

export interface DiscoveryStarRatingProps {
    rating?: number;
    maxStars?: number;
    reviewCount?: number;
    summary?: string;
}

interface StarIconProps {
    filled?: boolean;
    half?: boolean;
}

const StarIcon = ({ filled, half }: StarIconProps) => {
    const className = `omniguide-pr-star-rating__icon ${
        half ? 'omniguide-pr-star-rating__icon--half' :
            filled ? 'omniguide-pr-star-rating__icon--filled' : 'omniguide-pr-star-rating__icon--empty'
    }`;

    if (half) {
        return (
            <svg
                className={className}
                viewBox="0 0 20 20"
                fill="currentColor"
            >
                <defs>
                    <linearGradient id="halfFill">
                        <stop offset="50%" stopColor="#F59E0B" />
                        <stop offset="50%" stopColor="#D1D5DB" />
                    </linearGradient>
                </defs>
                <path
                    fill="url(#halfFill)"
                    d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z"
                />
            </svg>
        );
    }

    return (
        <svg
            className={className}
            viewBox="0 0 20 20"
            fill="currentColor"
        >
            <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" />
        </svg>
    );
};

export const DiscoveryStarRating = memo(function DiscoveryStarRating({
    rating = 0,
    maxStars = 5,
    reviewCount = 0,
}: DiscoveryStarRatingProps): JSX.Element {
    const stars: JSX.Element[] = [];
    const normalizedRating = Math.min(Math.max(rating, 0), maxStars);

    for (let i = 1; i <= maxStars; i++) {
        if (i <= Math.floor(normalizedRating)) {
            stars.push(<StarIcon key={i} filled />);
        } else if (i === Math.ceil(normalizedRating) && normalizedRating % 1 >= 0.25) {
            stars.push(<StarIcon key={i} half />);
        } else {
            stars.push(<StarIcon key={i} filled={false} />);
        }
    }

    return <div className="omniguide-pr-star-rating">{stars}{reviewCount > 0 && ` (${reviewCount})`}</div>;
});
