import React from 'react';
import type { ReconnectAttemptInfo } from '@swiftotter/omniguide-core';
import { useCountdown } from '../../hooks/useCountdown.js';

export interface SearchConnectionBannerProps {
    status: 'reconnecting' | 'disconnected';
    onRetry?: () => void;
    reconnectInfo?: ReconnectAttemptInfo | null;
}

/**
 * Inline banner shown in the chat area when the connection drops mid-conversation.
 * Two modes:
 * - 'reconnecting': pulsing dot + "Trying to reconnect in 3s (2/5)"
 * - 'disconnected': warning icon + "Unable to connect" + retry button
 */
export const SearchConnectionBanner: React.FC<SearchConnectionBannerProps> = ({
    status,
    onRetry,
    reconnectInfo,
}) => {
    const countdown = useCountdown(reconnectInfo, status === 'reconnecting');

    if (status === 'reconnecting') {
        const attemptText = reconnectInfo
            ? ` (${reconnectInfo.attempt}/${reconnectInfo.maxAttempts})`
            : '';
        const mainText = countdown !== null && countdown > 0
            ? `Trying to reconnect in ${countdown}s${attemptText}`
            : `Reconnecting...${attemptText}`;

        return (
            <div
                className="omniguide-connection-banner omniguide-connection-banner--reconnecting"
                role="status"
                aria-live="polite"
            >
                <span className="omniguide-connection-banner__dot" aria-hidden="true" />
                <span className="omniguide-connection-banner__text">
                    {mainText}
                </span>
            </div>
        );
    }

    return (
        <div
            className="omniguide-connection-banner omniguide-connection-banner--disconnected"
            role="status"
            aria-live="polite"
        >
            <svg className="omniguide-connection-banner__icon" width="14" height="14" viewBox="0 0 20 20" fill="currentColor" aria-hidden="true">
                <path
                    fillRule="evenodd"
                    d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 2.98-1.742 2.98H4.42c-1.53 0-2.493-1.646-1.743-2.98l5.58-9.92zM11 13a1 1 0 11-2 0 1 1 0 012 0zm-1-8a1 1 0 00-1 1v3a1 1 0 002 0V6a1 1 0 00-1-1z"
                    clipRule="evenodd"
                />
            </svg>
            <span className="omniguide-connection-banner__text">Unable to connect</span>
            {onRetry && (
                <button
                    type="button"
                    className="omniguide-connection-banner__retry-btn"
                    onClick={onRetry}
                >
                    Try Again
                </button>
            )}
        </div>
    );
};
