/**
 * Hook for managing WebSocket connection lifecycle
 *
 * Platform-agnostic — works with any ChatWebSocket from omniguide-core.
 */

import { useState, useCallback, useRef, useEffect } from 'react';
import { ChatWebSocket, createScopedLogger } from '@swiftotter/omniguide-core';
import type { ConnectionStatus, ReconnectAttemptInfo } from '@swiftotter/omniguide-core';
import type { UseChatConnectionOptions, UseChatConnectionReturn } from '../types.js';

const log = createScopedLogger('useChatConnection');

export const useChatConnection = ({
    websiteId,
    apiBaseUrl,
    sessionId,
    onMessage,
    conversationIdRef,
    autoConnect = true,
    connectionTimeout,
}: UseChatConnectionOptions): UseChatConnectionReturn => {
    const [connectionStatus, setConnectionStatus] = useState<ConnectionStatus>('disconnected');
    const [reconnectInfo, setReconnectInfo] = useState<ReconnectAttemptInfo | null>(null);
    const [hasAttemptedConnection, setHasAttemptedConnection] = useState(false);
    const isConnectingRef = useRef(false);
    const wsRef = useRef<ChatWebSocket | null>(null);

    /**
     * Initialize WebSocket connection.
     * Safely cleans up any existing instance before creating a new one.
     * Guards against rapid re-entry (e.g. double-clicking "Try Again").
     */
    const connect = useCallback(async () => {
        setHasAttemptedConnection(true);

        // Already connected — nothing to do
        if (wsRef.current?.isConnected()) {
            return;
        }

        // Guard against rapid re-entry (double-click "Try Again")
        if (isConnectingRef.current) {
            return;
        }
        isConnectingRef.current = true;

        // Clean up old instance (cancel its pending reconnect timers, close socket)
        if (wsRef.current) {
            wsRef.current.disconnect();
            wsRef.current = null;
        }

        try {
            wsRef.current = new ChatWebSocket({
                websiteCode: websiteId,
                apiBaseUrl,
                sessionId: sessionId || '',
                connectionTimeout,
                onMessage,
                onStatusChange: (status: ConnectionStatus) => {
                    setConnectionStatus(status);
                    // Clear reconnect info when connected or fully disconnected
                    if (status === 'connected' || status === 'disconnected') {
                        setReconnectInfo(null);
                    }
                },
                onError: (err: Error) => {
                    log.debug('WebSocket error:', err.message);
                },
                onReconnectAttempt: setReconnectInfo,
            });

            // Set the current conversation ID (empty string if new conversation)
            wsRef.current.setConversationId(conversationIdRef.current || '');

            log.debug('Connecting to WebSocket:', { websiteId, apiBaseUrl });
            await wsRef.current.connect();
        } finally {
            isConnectingRef.current = false;
        }
    }, [websiteId, apiBaseUrl, sessionId, onMessage, conversationIdRef, connectionTimeout]);

    /**
     * Disconnect WebSocket
     */
    const disconnect = useCallback(() => {
        if (wsRef.current) {
            wsRef.current.disconnect();
            wsRef.current = null;
        }
    }, []);

    /**
     * Send a query through the WebSocket
     */
    const sendQuery = useCallback((content: string, metadata: Record<string, unknown> = {}) => {
        if (wsRef.current) {
            wsRef.current.sendQuery(content, metadata);
        }
    }, []);

    /**
     * Reset the WebSocket connection (for starting new conversations)
     */
    const resetConnection = useCallback(() => {
        if (wsRef.current) {
            wsRef.current.reset();
        }
    }, []);

    /**
     * Check if connected
     */
    const isConnected = useCallback(() => {
        return wsRef.current?.isConnected() || false;
    }, []);

    /**
     * Update conversation ID on the WebSocket
     */
    const setWebSocketConversationId = useCallback((conversationId: string | null) => {
        if (wsRef.current) {
            wsRef.current.setConversationId(conversationId || '');
        }
    }, []);

    // Auto-connect on mount if enabled
    useEffect(() => {
        if (autoConnect) {
            connect().catch((err) => {
                log.debug('Auto-connect failed:', (err as Error).message);
            });
        }

        return () => {
            disconnect();
        };
    }, [autoConnect, connect, disconnect]);

    return {
        connectionStatus,
        hasAttemptedConnection,
        reconnectInfo,
        connect,
        disconnect,
        sendQuery,
        resetConnection,
        isConnected,
        setWebSocketConversationId,
    };
};
