import React from 'react';
import { ExpandIcon } from './Icons.js';
import { LoadingState } from './StateComponents.js';
import { ErrorState } from './StateComponents.js';
import { GoodFitResult as DefaultGoodFitResult } from './GoodFitResult.js';
import { NotFitResult as DefaultNotFitResult } from './NotFitResult.js';
import { FitResultsHeader } from './FitResultsHeader.js';
import { FitResultsFooter } from './FitResultsFooter.js';
import { useComponent } from '../../hooks/useComponent.js';
import type { FitProduct } from './ProductComparisonCard.js';
import type { FeedbackData } from '../discovery/DiscoveryFeedbackWidget.js';

export interface FitResult {
    fitEvaluation?: { is_good_fit?: boolean };
    fitExplanation?: {
        why_good_fit?: string[];
        why_not_good_fit?: string[];
    };
    alternative?: FitProduct & { why_better_for_you?: string[] };
    currentProduct?: FitProduct | null;
}

export interface FitResultsPanelProps {
    fitResult?: FitResult | null;
    isLoading?: boolean;
    error?: { message?: string; code?: string } | null;
    statusMessage?: string;
    onBack?: () => void;
    questions?: Array<{ id?: string; question?: string; summary?: string }>;
    answeredIntents?: Record<string, { answer: string; [key: string]: unknown }>;
    onStepClick?: (index: number) => void;
    isCollapsed?: boolean;
    onCollapseToggle?: () => void;
    isTruncated?: boolean;
    onTruncatedToggle?: () => void;
    /** DI: analytics callback when user clicks alternative product */
    onProductClick?: (name: string, sku: string | undefined, url: string) => void;
    /** DI: analytics callback for start-over action */
    onStartOver?: () => void;
    /** DI: callback for feedback submission */
    onFeedbackSubmit: (data: FeedbackData) => Promise<unknown>;
}

/**
 * FitResultsPanel - Displays fit evaluation results.
 * Shows either a "Great Match" card or a "Not the Best Match" card with alternatives.
 */
export function FitResultsPanel({
    fitResult,
    isLoading,
    error,
    statusMessage,
    onBack,
    questions = [],
    answeredIntents = {},
    onStepClick,
    isCollapsed = false,
    onCollapseToggle,
    isTruncated = false,
    onTruncatedToggle,
    onProductClick,
    onStartOver,
    onFeedbackSubmit,
}: FitResultsPanelProps): JSX.Element | null {
    const GoodFitResult = useComponent('GoodFitResult', DefaultGoodFitResult);
    const NotFitResult = useComponent('NotFitResult', DefaultNotFitResult);

    const headerProps = { questions, answeredIntents, onStepClick };

    // Loading state
    if (isLoading) {
        return (
            <div className="omniguide-pr-results">
                <FitResultsHeader {...headerProps} />
                <LoadingState statusMessage={statusMessage} />
            </div>
        );
    }

    // Error state
    if (error) {
        return (
            <div className="omniguide-pr-results">
                <ErrorState error={error} onRetry={onBack} />
            </div>
        );
    }

    // No result yet
    if (!fitResult) return null;

    const { fitEvaluation, fitExplanation, alternative } = fitResult;
    const isGoodFit = fitEvaluation?.is_good_fit ?? true;

    const fitContent = isGoodFit ? (
        <GoodFitResult fitExplanation={fitExplanation} />
    ) : (
        <NotFitResult
            currentProduct={fitResult.currentProduct}
            fitExplanation={fitExplanation}
            alternative={alternative}
            onProductClick={onProductClick}
        />
    );

    // Collapsed state (desktop)
    if (isCollapsed) {
        const expandLink = (
            <button
                type="button"
                onClick={onCollapseToggle}
                className="omniguide-pr-results__expand-link"
                aria-expanded="false"
                aria-label="See our recommendation"
            >
                See our recommendation
            </button>
        );

        return (
            <div className="omniguide-pr-results omniguide-pr-results--collapsed">
                <FitResultsHeader
                    {...headerProps}
                    showCollapseBtn
                    isCollapsed
                    onCollapseToggle={onCollapseToggle}
                    titleExtra={expandLink}
                />
            </div>
        );
    }

    // Truncated state with "Show More" (mobile)
    if (isTruncated) {
        return (
            <div className="omniguide-pr-results omniguide-pr-results--truncated">
                <FitResultsHeader {...headerProps} showSubtitle />
                <div className="omniguide-pr-results__truncated-content">
                    <div className="omniguide-pr-results__truncated-preview">
                        {fitContent}
                    </div>
                    <div className="omniguide-pr-results__truncated-fade" />
                </div>
                <div className="omniguide-pr-results__show-more-container">
                    <button
                        type="button"
                        className="omniguide-pr-results__show-more-btn"
                        onClick={onTruncatedToggle}
                    >
                        <span>Show More</span>
                        <ExpandIcon />
                    </button>
                </div>
            </div>
        );
    }

    // Expanded state (default)
    return (
        <div className="omniguide-pr-results">
            <FitResultsHeader
                {...headerProps}
                showCollapseBtn
                isCollapsed={false}
                onCollapseToggle={onCollapseToggle}
                showSubtitle
            />
            {fitContent}
            {onBack && (
                <FitResultsFooter
                    fitResult={fitResult}
                    alternative={alternative}
                    onBack={onBack}
                    onStartOver={onStartOver}
                    onFeedbackSubmit={onFeedbackSubmit}
                />
            )}
        </div>
    );
}
