/**
 * Default config builders for the bundle.
 *
 * Maps the simplified BundleInitConfig to the full OmniguideConfig
 * and creates the appropriate platform adapter.
 */

import {
  DEFAULT_STORAGE_KEYS,
  createPlatformAdapter,
  getApiBaseUrl,
  type OmniguideConfig,
  type PlatformAdapter,
} from '@swiftotter/omniguide-core';

import { createBigCommerceAdapter } from '@swiftotter/omniguide-bigcommerce';

import type { BundleInitConfig } from './types.js';

/**
 * Build a full OmniguideConfig from a simplified BundleInitConfig.
 */
export function buildConfig(userConfig: BundleInitConfig): OmniguideConfig {
  const apiBaseUrl = getApiBaseUrl(userConfig.apiBaseUrl);

  return {
    websiteId: userConfig.websiteId,
    apiBaseUrl,
    aiSearchStoreUrl: userConfig.aiSearchStoreUrl,
    features: {
      search: true,
      productFit: true,
      categoryGuide: true,
      discoveryQuestions: true,
      ...userConfig.features,
    },
    selectors: userConfig.selectors,
    fallbackImages: userConfig.fallbackImages,
    ui: userConfig.ui,
    callbacks: userConfig.callbacks,
    analyticsAdapter: userConfig.analyticsAdapter,
    consent: userConfig.consent,
    storageKeys: userConfig.storageKeys ?? DEFAULT_STORAGE_KEYS,
    categoryUrl: userConfig.categoryUrl,
    connectionTimeout: userConfig.connectionTimeout,
    currentPage: userConfig.currentPage,
    productHydrationEndpoint: userConfig.productHydrationEndpoint,
    categoryHydrationEndpoint: userConfig.categoryHydrationEndpoint,
  };
}

/**
 * Build a platform adapter from a BundleInitConfig.
 *
 * - 'bigcommerce' (default): creates a BigCommerce adapter that reads BCData/storeConfig
 * - 'generic': creates a generic adapter with optional productSku passthrough
 */
export function buildPlatformAdapter(userConfig: BundleInitConfig): PlatformAdapter {
  const platform = userConfig.platform ?? 'bigcommerce';

  if (platform === 'generic') {
    // Generic mode: no platform globals needed.
    // If productSku is provided, expose it via getProductSku().
    const productSku = userConfig.productSku ?? null;
    return createPlatformAdapter({
      getPlatformName: () => 'generic',
      isInitialized: () => true,
      getProductSku: () => productSku,
    });
  }

  // BigCommerce mode (default)
  const apiBaseUrl = getApiBaseUrl(userConfig.apiBaseUrl);
  return createBigCommerceAdapter({
    apiBaseUrl,
    websiteId: userConfig.websiteId,
    productHydrationEndpoint: userConfig.productHydrationEndpoint,
    categoryHydrationEndpoint: userConfig.categoryHydrationEndpoint,
  });
}
